insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-pif-implementation', 'e7c51b59159139a2ceb449186a11892a77840cbfe6c1a19912ff7e621e4ef5c5', '2026-06-25T13:02:08.995Z', true, 46333, 3215, 'data/knowledge/documents/tw-tfda-pif-implementation.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: you are in： Home News &amp; Events News & Events Cosmetic Product Information Files (PIF) to Be Implemented in Phases Annually 【Update Date： 2025-08-14 】 unit：醫療器材及化粧品組 To enhance the safety of cosmetic use, the Ministry of Health and Welfare has been implementing the Product Information File (PIF) system in phases since 2019. Starting July 1, 2024, PIFs have been required for sunscreens, hair dyes, perm agents, antiperspirants, and home-use tooth whitening products containing peroxide. From July 1, 2025, cosmetics for babies, lips, eyes, as well as general toothpaste and mouthwash, must also comply. Finally, beginning July 1, 2026, all cosmetic products—except handmade solid soaps produced by entities exempt from factory registration—must have a PIF established before being marketed, sold, or provided for consumer use. Each PIF must include 16 items such as product details, ingredient names and concentrations, manufacturing process, toxicological data, stability test reports, and a comprehensive safety assessment, all signed by a qualified safety assessor. This ensures safety through thorough documentation and scientific evaluation. To facilitate regulatory compliance, the Taiwan Food and Drug Administration (TFDA) offers the Guidelines on the Establishment of Cosmetic Product Information File , along with documents templates for various product types (e.g., sunscreens, hair dyes, perm agent).Online training is also available via the Medical Device and Cosmetic e-Learning Platform ( https://mdcel.fda.gov.tw/mooc/explorer.php ) to help businesses better understand the applicable requirements and successfully establish their product information files. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"cosmetics","tags":["pif","safety-assessment","2026"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/newsContent.aspx?id=31164","extra_fetched_urls":[],"cache_days":14,"cache_expires_at":"2026-07-09T13:02:08.995Z","cache_status":"fresh","browser_capture_path":null,"screenshot_pa