insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-imported-cosmetics-inspection', 'Regulations for the Inspection and Examination of Imported Cosmetics', 'https://www.fda.gov.tw/ENG/lawContent.aspx?cid=5062&id=3191', 'Taiwan Food and Drug Administration', 'TW', 'cosmetics_import', 'regulation', 'high', '["cosmetics","import-inspection","sampling","release","nonconforming-goods"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-imported-cosmetics-inspection', 'd3587c735a7707aa00496e7b674b63daec1831b43dee2abec55a4769b9c9cc0e', '2026-06-25T15:13:34.048Z', false, 79022, 12744, 'data/knowledge/documents/tw-tfda-imported-cosmetics-inspection.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Cosmetics Cosmetics Regulations for the Inspection and Examination of Imported Cosmetics 【Update Date： 2019-06-27 】 unit：醫療器材及化粧品組 【Announced Date： 2019-06-27 】 【Amended Date： 2019-06-27 】 Links Regulations for the Inspection and Examination of Imported Cosmetics News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended. Regulations for the Inspection and Examination of Imported Cosmetics - Article Content - Laws & Regulations Database of The Republic of China (Taiwan) Goto Main Content ::: Sitemap 中文 Search Search News Law Convention News Law Convention Searching Justices of the Constitutional Court Related Websites Sitemap 中文 ::: Location： Home Law Article Content P Print Select Folders： Save Save Add New Folder Manage Folders Article Content Title： Regulations for the Inspection and Examination of Imported Cosmetics CH Announced Date： 2019-06-27 Category： Ministry of Health and Welfare（衛生福利部） Article Content Article Search Content Search Legislative History Article 1 These regulations have been established according to Paragraph 2 of Article 14 of the Cosmetic Hygiene and Safety Act (the “Act”). Article 2 Definition: terms used in these regulations: 1. Inspections: This refers to border checks or examination before permitting the importation of cosmetics. 2. Examination: This refers to conducting sensory, physical, chemical, or biological tests and experiments in a laboratory. 3. Inspection authorities: This refers to inspection enforcement by the central competent authority or its appointed agencies (organizations), orporations, or groups. 4. Obligatory inspection applicants: This refers to cosmetics importers. Article 3 For cosmetics required for inspection as promulgated by the competent authority in accordance with Paragraph 1 of Article 14 of the Act, the obligatory inspection applicants shall file an application for inspection and submit the following documents and information to the inspection authority at the port of entry within fifteen (15) days prior to the date of import: 1. A copy of the application for import declaration. 2. Necessary documents required by the inspection authority. The application of the preceding Paragraph can be submitted electronically. If the representative files the application of Paragraph 1, a letter of Power of Attorney and the identification documents for the representative, corporation, or business shall be submitted. Article 4 Cosmetics pursuant to Paragraph 1 of the preceding Article that conform to one of the following situations may be exempted from inspection: 1. Products to be imported are issued with a certificate of examination by the government of the country of origin who has signed an examination waiver reciprocity agreement with the government of the Republic of China. 2. Others with the special permit of the central competent authority. Article 5 The central competent authority shall inspect the compliance of imported cosmetics; the inspection shall not include the situations mentioned in Article 7 and Paragraph 1 of Article 10 of the Act. Obligatory inspection applicant shall legalize the items of the preceding Paragraph before the products were supplied, sold, gifted, publicly displayed, or offered for consumer trial. Article 6 In addition to documentation review (as prescribed in Paragraph 1 and Paragraph 3 of Article 3), inspection authority may carry out the inspection of imported cosmetics in one or some of the following measures: 1. On-site inspection: check items, inspect the appearance of the packaging, labels, and other related items on site. 2. Randomly-selected batch examination: perform based on a 2%-50% inspection rate. 3. Batch-by-batch examination: carry out for each submitted batch of imported cosmetics. Article 7 The samples required for inspection shall be taken free-of-charge. The maximum number (amount) of sampling shall be limited to what is required for inspection purpose. After collecting the samples, the authority shall issue a receipt to the obligatory inspection applicant. For the sampling mentioned in the preceding Paragraph, the obligatory inspection applicant shall not designate the sample. Article 8 The inspection and sampling shall be conducted at the storage site of products. If the products shipped in full container load, the inspection and sampling shall be conducted at the centralized inspection area or the specified zone approved by Taiwan Food and Drug Administration of the Ministry of Health and Welfare (TFDA). Article 9 The examination of imported cosmetics shall be conducted in the order of sampling. However, the original examination laboratory shall prioritize inspection on products applying for re-examination according to Paragraph 2 of Article 12. Article 10 Due to the difficulty of sampling in a container yard, requiring five or more days for examination, or deterioration or lack of stability of cosmetics, the inspection authority may issue a notice of prior release for import for customs clearance after the obligatory inspection applicant signs an affidavit of custodial responsibility. If the pledged storage location does not conform to the actual storage location, or for anyone who intentionally uses, moves, provides, sells or gifts cosmetics before issuing the import permit, the inspection authority may suspend the acceptance of an application for prior release of import by the obligatory inspection applicant within 180 days from the day of discovery. Article 11 After imported cosmetics applied for inspection are found to conform to the regulations, the inspection authority shall issue an import permit to the obligatory inspection applicant. The obligatory inspection applicant may apply to the inspection authority for a written permit. The obligatory inspection applicant shall claim the remaining samples by presenting the sampling receipt within 15 days after receiving the permission. However, if the sample is not claimed within the statutory period or has a short shelf life, the inspection authority may dispose of the samples directly. Article 12 In the event the imported cosmetics fail to conform to regulations, the inspection authority shall issue a notification of noncompliance for cosmetics to the obligatory inspection applicant. The obligatory inspection applicant may apply for re-examination to the original insp', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"cosmetics_import","tags":["cosmetics","import-inspection","sampling","release","nonconforming-goods"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/ENG/lawContent.aspx?cid=5062&id=3191","extra_fetched_urls":["https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0030102"],"cache_days":30,"cache_expires_at":"2026-07-25T15:13:34.048Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-cosmetics-management-transition-2021', 'New Cosmetics Management System to Be Enforced from July 2021', 'https://www.fda.gov.tw/eng/newsContent.aspx?id=26899', 'Taiwan Food and Drug Administration', 'TW', 'cosmetics', 'notice', 'medium', '["cosmetics","notification","labeling","transition","general-cosmetics"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-cosmetics-management-transition-2021', '26a0bc8ca1366f52cdc5033f594f10aad1f01203002039a05c2952d112777cb8', '2026-06-25T15:09:13.960Z', false, 45795, 3639, 'data/knowledge/documents/tw-tfda-cosmetics-management-transition-2021.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: you are in： Home News &amp; Events News & Events New Cosmetics Management System to be Enforced from July 2021 【Update Date： 2021-03-30 】 unit：醫療器材及化粧品組 In order to fully and thoroughly satisfy the provisions of the Cosmetic Hygiene and Safety Act, from July 1, 2021, new management systems such as regarding general toothpaste and mouthwash products as cosmetics, notification systems for the general cosmetics, and labeling requirements for cosmetic packaging, containers, labels or leaflets will be implemented to enhance the safety management of cosmetics, improve the product hygiene and safety, and protect the rights and benefits of consumers. Taiwan Food and Drug Administration (Taiwan FDA) has stated that from July 1, 2021, general toothpaste and mouthwash products will be included in the management for cosmetics, and hence, the labeling, ingredients, quality, hygiene and safety, and manufacturing facilities of these products shall comply with regulations for cosmetics. It is expected to enhance the quality, hygiene and safety of general toothpaste and mouthwash products. General cosmetics shall be notified at the “Cosmetic Products Notification Platform System” established by Taiwan FDA prior to their supply, sale, giveaway, public display, or consumer trial offer of cosmetics. It would be helpful for the competent authority to monitor the items and obtain related information on cosmetics available in the domestic market. New regulations for cosmetics labeling provide clear rules for the items of cosmetics labeling, standardization for the display order of ingredients, and the font sizes of items required to be labeled, which could help consumers to identify directly and check the product information and further improve consumer rights. In addition, to prompt people from all walks of life understand our regulations, Taiwan FDA has released a video titled “The Current and Future Cosmetics Regulations and PIF” on the website named “Medical Device and Cosmetic e-Learning system”. Please visit this website at http://mdcel.fda.gov.tw/info/10000252 for more information. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"cosmetics","tags":["cosmetics","notification","labeling","transition","general-cosmetics"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/newsContent.aspx?id=26899","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T15:09:13.960Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-moj-cosmetic-product-notification', 'Regulations Governing Notification of Cosmetic Products', 'https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0030097', 'Ministry of Health and Welfare / MOJ Laws and Regulations Database', 'TW', 'cosmetics', 'regulation', 'high', '["cosmetics","product-notification","ingredients","importers"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-moj-cosmetic-product-notification', '79579a506e998fcbd661187321e29f54a71eba9247735851ca16e582950b4455', '2026-06-25T13:02:09.530Z', true, 28376, 5643, 'data/knowledge/documents/tw-moj-cosmetic-product-notification.md', 'Regulations Governing Notification of Cosmetic Products - Article Content - Laws & Regulations Database of The Republic of China (Taiwan) Goto Main Content ::: Sitemap 中文 Search Search News Law Convention News Law Convention Searching Justices of the Constitutional Court Related Websites Sitemap 中文 ::: Location： Home Law Article Content P Print Select Folders： Save Save Add New Folder Manage Folders Article Content Title： Regulations Governing Notification of Cosmetic Products CH Announced Date： 2019-05-30 Category： Ministry of Health and Welfare（衛生福利部） Article Content Article Search Content Search Legislative History Article 1 This Regulation is enacted pursuant to Paragraph 2 of Article 4 of Cosmetics Hygiene and Safety Act (the “Act”). Article 2 The cosmetics manufacturers or importers of a certain scale under Paragraph 1 of Article 4 of the Act (the “Cosmetics Manufacturers or Importers”) shall refer to below entities in the business of manufacturing or importing cosmetics products: 1. A corporate or a firm to be established and registered pursuant to Company Act and/or Business Registration Act. 2. A factory to be registered pursuant to Paragraph 1 of Article 8 of the Act. 3. The groups and corporations which engage in cosmetics manufacturing or importing, except the handmade soap entities which are exempt from industry registration, excluding the entities mentioned in preceding two subparagraphs. Article 3 Cosmetics Manufacturers or Importers shall, while manufacturing or importing cosmetics under Paragraph 1 of Article 4 of the Act, complete data notification via the platform provided by the central competent authorities. Article 4 Data notification specified in the preceding Article shall include: 1. Notification number of products. 2. Chinese and English names of products provided that no need to notify the English name of domestic products. 3. Category and usage of products. 4. Type of products. Model number and color code for series products. 5. Dosage of products. 6. Precautions of products. 7. Names, addresses and telephone numbers of manufacturers or importers of products. 8. Names, addresses nationalities of the premises where products manufactured and other criteria conforming to cosmetics Good Manufacturing Practice (GMP). 9. Full components of products. Weight or capacity percentage identifying its content inclusion if limitation of usage set forth by the central competent authorities. 10. Other relevant descriptions. The aforesaid data notify shall be made in Chinese, English, numbers or international symbols. Article 5 No false data notify shall be provided by Cosmetics Manufacturers or Importers. Article 6 Data notification shall be made separately for different data provided for each Sub-paragraph of Paragraph 1 of Article 4, except for the followings: 1. Multiple product names carrying same component formula, dosage and usage. 2. Same series products carrying same dosage and usage with only difference in pigments or spices and/or essence of component formula. 3. Combination products referring to those products including more than two cosmetics products which are not able to be supplied, sold, gave away, public display, or offered consumer trial. Article 7 Changes of cosmetics product data notification may be by amendment except for the change involving components, which shall be made by re-notification its data notification. Article 8 The valid period for cosmetics product data notification is three years. If after the three year term, products are still supplied, sold, gave away, public display, or offered consumer trial, the data notification valid period shall be extended three months prior to its expiration. Article 9 The data notification shall be disapproved if there is any of the following: 1. Data notification denied pursuant to Paragraph 2 of Article 22, Paragraph 2 of Article 23, Paragraph 2 of Article 24 of the Act. 2. Products containing any components prohibited to be used via the announcement made by the central competent authorities. 3. Incomplete data notification pursuant to Article 4. Article 10 Data notification made by those Cosmetics Manufacturers or Importers who are dissolved or have closed its business, or whose corporation registration, business registration, factory registration or other equivalent registration or permits were withdrawn or abolished, shall be revoked. Cosmetics Manufacturers or Importers may revoke data notification of a product if the product is no longer supplied, sold, gave away, public display, or offered consumer trial. Article 11 The central competent authorities shall rescind the data notification if found products, after completion of data notification, are not cosmetics defined under Sub-paragraph 1 of Paragraph 1 of Article 3 of the Act. Article 12 The Regulations shall take effect on July 1, 2019. ::: News Law Convention Searching Justices of the Constitutional Court Related Websites E-PAPER VISITORS 43,462,524 MONTHLY VISITORS 388,679 ONLINE VISITORS 66 E-PAPER SUBSCRIBERS 20,728 This website does not provide legal counseling service, please contact with related public offices for more information. In case of any discrepancy between the English version and the Chinese version, the latter shall prevail. The last update date of laws and regulations data：2026/06/18 │ Open Data Statement │ Declaration on Privacy Right Protection │ Information Security Policy │ EMail │ OPERATING BY THE WORKING GROUP OF THE R.O.C LAWS & REGULATIONS DATABASE, MINISTRY OF JUSTICE. NO. 130, Sec. 1, Chongqing S. Rd., Taipei, 100204, Taiwan(R.O.C.) Service Phone-Call: +886-2-2191-0189 Top', '{"source_registry_version":"2026-06-26","authority":"Ministry of Health and Welfare / MOJ Laws and Regulations Database","domain":"cosmetics","tags":["cosmetics","product-notification","ingredients","importers"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0030097","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:09.530Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-moj-cosmetic-pif-management', 'Regulations for Cosmetic Product Information File Management', 'https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0030098', 'Ministry of Health and Welfare / MOJ Laws and Regulations Database', 'TW', 'cosmetics', 'regulation', 'high', '["cosmetics","pif","safety-assessment","ingredient-content"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-moj-cosmetic-pif-management', '44df9f416b5f7dbdcc46200f5b8431d6f3b972200321aec2173f98259895922a', '2026-06-25T13:02:09.708Z', true, 30787, 8193, 'data/knowledge/documents/tw-moj-cosmetic-pif-management.md', 'Regulations for Cosmetic Product Information File Management - Article Content - Laws & Regulations Database of The Republic of China (Taiwan) Goto Main Content ::: Sitemap 中文 Search Search News Law Convention News Law Convention Searching Justices of the Constitutional Court Related Websites Sitemap 中文 ::: Location： Home Law Article Content P Print Select Folders： Save Save Add New Folder Manage Folders Article Content Title： Regulations for Cosmetic Product Information File Management CH Amended Date： 2022-06-16 Category： Ministry of Health and Welfare（衛生福利部） Article Content Article Search Content Search Legislative History Article 1 The regulations are prescribed pursuant to Paragraph 3 of Article 4 of the Cosmetic Hygiene and Safety Act (hereinafter referred to as "the Act"). Article 2 The cosmetics manufacturers or importers of a certain scale (hereinafter referred to as " cosmetics manufacturers or importers ") mentioned in Paragraph 1 of Article 4 of the Act shall mean the following entities which engage in cosmetics manufacturing or importing: 1. The companies and businesses which shall apply for registration according to the Company Act and Business Registration Act. 2. The factories which shall complete registration according to Paragraph 1 of Article 8 of the Act. 3. The groups and corporations which engage in cosmetics manufacturing or importing, except the handmade soap entities which are exempt from industry registration, excluding the entities mentioned in preceding two subparagraphs. Article 3 Cosmetic product information file shall establish the following information in Chinese or English: 1. Basic information of the product: the name of the product, the category of the product, dosage form, purpose, the names and addresses of manufacturing facilities, information of product manufacturers or importers. 2. Evidentiary documents of completing product notification. 3. Full ingredient names and the individual content. 4. The outer packaging of the products, containers, labels or leaflets. 5. GMP compliance certificates or self-declarations which the manufacturing facilities comply with cosmetic Good Manufacturing Practice Regulations 6. Manufacturing methods and procedures. 7. Usage methods, body parts, dosage, frequencies and the targeted population. 8. Adverse effects of the product application. 9. Physical and chemical characteristics of the products and individual ingredients. 10. Toxicological data of the ingredients. 11. The product stability test reports. 12. The microbiological test reports. 13. The antimicrobial effectiveness test reports. 14. Supporting information of the functional assessments. 15. Information about the packaging materials which have contact with the products. 16. Product safety information: (1) Safety evaluation conclusion and suggestion which has the signature of the signatory for the safety report and the date. (2) Qualification certificates which the signatory for the safety report complies with Article 4, 5 and 6. If the original information of the file in the preceding paragraph is established in the language other than Chinese or English, the Chinese or English translation shall be attached Cosmetic products which are manufactured in separate processes, the names and addresses of manufacturing facilities mentioned in the Subparagraph 1 of the previous paragraph shall include all of the manufacturing facilities in the processes and their operation procedures. Cosmetic product information file shall be renewed in accordance with Paragraph 1 when it changes. The information mentioned Subparagraph 11 to 13 of Paragraph 1, when the signatory for the safety report evaluates the characteristics or specialty of the product and makes reasoning in Subparagraph 16 of the same Paragraph, may be exempt from establishment. Article 4 A person who has taken cosmetic safety evaluation training courses which are provided domestic or foreign university which complies with Regulations Governing the Assessment and Recognition of Foreign Academic Records by Institutions of Higher Education (hereinafter referred to as " domestic or foreign university"), or by central competent authority, and complied with the following conditions, the person may serve as a signatory for the safety report of product information file mentioned in Subparagraph 16 of Paragraph 1 of the preceding article: 1. who graduated from department of medicine, department of pharmacy, or toxicology, cosmetic and other related departments or graduate schools at the domestic university or the foreign university. 2. Who graduated from the department of chemistry or chemical engineering at the domestic or foreign university before 2019.6.30, and had at least five years of relevant work experience in cosmetic safety evaluation. The content and hours of cosmetic safety evaluation training courses mentioned in the preceding paragraph shall be: 1. Cosmetic management regulations: including cosmetic hygiene management regulations of R.O.C (Taiwan), international cosmetic hygiene regulations, and the system of cosmetic product information file in R.O.C. (Taiwan); at least 4 hours. 2. Applications and risks of cosmetic ingredients: including the action principles and safety of whitening, sunscreen, antiperspirant, deodorant, hair-dyeing, permanent waving and other ingredients, and common cosmetic adverse effects and violations; at least 8 hours. 3. Methods of cosmetic safety evaluation: including skin anatomy and physiology, cosmetic percutaneous absorption capacity, skin irritation, the mechanism and symptom of photoaging and photoallergy, the safety evaluation of nanomaterials, the safety evaluation of natural substance cosmetic, the cosmetic risk assessment, toxicological evaluation methods(skin irritation, skin sensitization, skin corrosivity, eye irritation and genetic toxicity and mutagenicity test), systemic toxicity and margin of safety, and alternative methods of animal testing; at least 36 hours. 4. Concluding the product safety evaluation: at least 6 hours. Article 5 The signatory for the safety report of product information file shall take at least eight hours courses yearly which are provided by the domestic or foreign university, or by central competent authority, and the courses shall relate to Paragraph 2 of the preceding article. Article 6 The countries (regions) or areas which have signed the cooperation agreements of the signatory for the safety report of product information file with R.O.C (Taiwan), their signatories are exempted from the application of Paragraph1 of Article 4 and the preceding article. Article 7 The cosmetic product information file may be stored by written records or the means of electronic data storage media. The file stated in the preceding paragraph shall be kept for at least five years from the next day of the date of the product lastly available in the market. Article 8 The cosmetics manufacturers or importers shall store the product information file at the address mentioned in Subparagraph 7 of Paragraph 1 of Article 7 of the Act and provide it for the competent authority inspection. The competent authority shall send a notification at least seven days before it assigns officers to inspect the file mentioned in the preceding paragraph unless the emergency or the need of public interests. Article 9 The Regulations shall take effect on July 1, 2019. ::: News Law Convention Searching Justices of the Constitutional Court Related Websites E-PAPER VISITORS 43,462,525 MONTHLY VISITORS 388,680 ONLINE VISITORS 67 E-PAPER SUBSCRIBERS 20,728 This website does not provide legal counseling service, please contact with related public offices for more information. In case of any discrepancy between the English version and the Chinese version, the latter shall prevail. The last update date of laws and regulations data：2026/06/18 │ Open Data Statement │ Declaration on Privacy Right Protection │ Information Security Policy │ EMail │ OPERATI', '{"source_registry_version":"2026-06-26","authority":"Ministry of Health and Welfare / MOJ Laws and Regulations Database","domain":"cosmetics","tags":["cosmetics","pif","safety-assessment","ingredient-content"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0030098","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:09.708Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-moj-food-safety-sanitation-act', 'Act Governing Food Safety and Sanitation', 'https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0040001', 'Ministry of Health and Welfare / MOJ Laws and Regulations Database', 'TW', 'food_labeling', 'law', 'high', '["food","labeling","food-additives","import"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-moj-food-safety-sanitation-act', '315b80cc5c83722cc1b4fa38efd311fd49b3f0f74d25a5a0e1b67dc15af45a7c', '2026-06-25T13:02:10.220Z', true, 100920, 72171, 'data/knowledge/documents/tw-moj-food-safety-sanitation-act.md', 'Act Governing Food Safety and Sanitation - Article Content - Laws & Regulations Database of The Republic of China (Taiwan) Goto Main Content ::: Sitemap 中文 Search Search News Law Convention News Law Convention Searching Justices of the Constitutional Court Related Websites Sitemap 中文 ::: Location： Home Law Article Content P Print Select Folders： Save Save Add New Folder Manage Folders Article Content Title： Act Governing Food Safety and Sanitation CH Amended Date： 2019-06-12 Category： Ministry of Health and Welfare（衛生福利部） Article Content Chapter Article Search Content Search Legislative History Chapter I General Principles Article 1 This Act is enacted to govern the food sanitation, safety, and quality, and protect public health. Article 2 For purposes of this Act, the term "competent authority" shall mean the central competent authority in charge of health and welfare at the central government level, the municipal governments at the municipal level, and the county (city) governments at the county (city) level. Article 2-1 To enhance the coordination, oversight, promotion, and investigation of national food safety affairs, the Executive Yuan shall establish the Food Safety Board. The Premier of the Executive Yuan shall serve as the convener with the participation of the heads of other relevant ministries and commissions, experts, scholars, and representatives of non-governmental organizations to take charge of inter-agency coordination for the food safety risk assessment and management measures as well as establish the early warning and auditing system of food safety and sanitation. The Food Safety Board shall meet at least once every three months. When necessary, a temporary meeting may be convened. The convener shall appoint a Minister without Portfolio or a head of ministries and commissions to act as the Chief Executive of the Food Safety Board and the central competent authority shall be in charge of staff affairs. Each municipal and county (city) government shall establish the Food Safety Board; the head of the municipality and county (city) shall serve as the convener to take charge of inter-departmental coordination for the food safety and sanitation management measures. A meeting shall be convened at least once every three months. Decisions made by the Food Safety Board in Paragraph 1 shall be carried out and implemented in compliance by relevant ministries and commissions. Each quarter, the Executive Yuan shall announce the supervision results and include them in its administrative policies report to the Legislative Yuan every year. The regulations governing the formation, tasks, meeting procedures and other matters to be complied with for such Food Safety Board in Paragraph 1 shall be prescribed by the Executive Yuan. Article 3 For purposes of this Act, the following terms shall have the meaning set forth below: 1. The term “foods” shall mean goods provided to people for eating, drinking, or chewing, and the raw materials of such goods. 2. The term “special dietary foods” shall mean infant and follow-up formula, formula for certain diseases or other formula approved by the central competent authority to be consumed by people with special nutrient requirement. 3. The term "food additives" shall mean a single substance or combination of substances that are added to or brought into contact with foods for the purpose of coloring, seasoning, preserving, bleaching, emulsifying, flavoring, stabilizing quality, enhancing fermentation, increasing viscosity, enriching nutritional value, preventing oxidation or other necessary purpose. Components of the food additive combinations shall be limited to food additives approved by the central competent authority. The single food additive shall have an approval number granted by the central competent authority. 4. The term "food utensils" shall mean instruments, tools, or containers that come into direct contact with foods or food additives. 5. The terms "food containers or packaging" shall mean containers and packaging materials that come into direct contact with foods and food additives. 6. The term "food cleansers" shall mean substances used to disinfect or clean foods, food utensils, food containers and food packaging. 7. The term "food business operators" shall mean those businesses that engage in the manufacture, processing, preparation, packaging, transportation, storage, sale, import or export of foods, or engage in the manufacture, processing, import, export or sale of food utensils, food containers or packaging, or food cleansers. 8. The term "labels" shall mean wording, pictures, symbols or additional instruction sheet affixed to foods, food additives, food cleansers, food utensils, food containers or food packaging to indicate the product name or to give explanation. 9. The term “nutrition label” shall mean the nutrients, contents or nutrition claims of the food affixed to food containers or packaging. 10. The term “inspection” shall mean verification and analysis. 11. The term “genetic modification” shall mean the transfer of genetic material or insertion into live cells or organisms via genetic engineering, molecular biotechnology, or other related technologies to produce genetic recombination, exogenous genetic characteristics, or to suppress certain genes of the recipient. However, this does not include traditional breeding methods or techniques such as cell and protoplast fusion, hybridization, mutagenesis, in-vitro fertilization, somaclonal variation, and chromosome doubling of plants of the same species and protoplasts. 12. The term “processing aid” shall mean any substance or material, not including apparatus or utensils, and not consumed as a food ingredient by itself, intentionally used in the processing of raw materials, foods or its ingredients, to fulfill a certain technological purpose during treatment or processing and which may result in the non-intentional but unavoidable presence of residues or derivatives in the final product. Any residues of processing aids shall be removed before the food reaches its finished form and remaining in the food after processing should not perform a function in the final product. Chapter II Risk Management for Food Safety Article 4 The actions taken by the competent authority in the governing of food safety and sanitation shall be based on risk assessment and shall align with satisfying the citizens’ right to have healthy and safe food and the right to know, as well as the principles of scientific evidence, precaution, and information transparency. The competent authority shall establish a risk assessment and advisory system. For the risk assessment mentioned in the preceding paragraph, the central competent authority shall assemble experts and scholars specialized in food safety, toxicology, risk assessment, etc., as well as non-governmental organizations, to form a food risk assessment advisory committee. Each gender shall not be less than one-third of the total number of the committee members. The advisory system in Paragraph 1 shall refer to a council advisory committee comprising experts and scholars specializing in food safety, nutrition, medicine, toxicology, risk management, agriculture, law, and humanities and social science to provide advice on food sanitation and safety, nutrition, genetically modified foods, food advertising and labeling, and food testing methods. Each gender shall not be less than one-third of the total number of the committee members. The members of the committee shall abide by the recusal regulation of Article 32 of the Administrative Procedure Act. The regulations governing the formation, proceedings, procedures, scope and other matters to be complied with for such council advisory committee shall be prescribed by the central competent authority. Whenever necessary, the central competent authority may take the following actions on specified products and products from specified areas on the basis of the precautio', '{"source_registry_version":"2026-06-26","authority":"Ministry of Health and Welfare / MOJ Laws and Regulations Database","domain":"food_labeling","tags":["food","labeling","food-additives","import"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0040001","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:10.220Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-food-nutrition-labeling', 'Regulations on Nutrition Labeling for Prepackaged Food Products', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1633', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'high', '["food","nutrition-label","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-nutrition-labeling', '211fc12e80c091bedca113cf0ff3e61ae246312578c9a82e2b15459e43eedac6', '2026-06-25T13:02:10.412Z', true, 81712, 16964, 'data/knowledge/documents/tw-tfda-food-nutrition-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations on Nutrition Labeling for Prepackaged Food Products 【Update Date： 2014-04-15 】 unit：食品組 【Announced Date： 2021-04-27 】 【Amended Date： 2021-04-27 】 Chapter I. General Provisions 1. This regulation is established under the provisions of Item 3 of Article 22 of the Act Governing Food Safety and Sanitation (hereinafter referred to as “this Act”). 2. The terms used in this regulation are defined as follows: 2.1 Trans fats (fatty acids): all the geometrical isomers of monounsaturated and polyunsaturated fatty acids having non-conjugated carbon-carbon double bonds in the trans configuration. 2.2 Carbohydrates: namely saccharides; the sum of carbohydrates. 2.3 Sugars: the sum of all free mono and disaccharides. 2.4 Dietary fibers: lignin and edible carbohydrate polymers with three or more monomeric units, which are not hydrolysed or absorbed by the endogenous enzymes in the small intestine of humans. 2.5 Nutrition claims: any representation which states, suggests or implies that a food product has particular calorie or nutrition properties. 3. The nutrition labeling for a prepackaged food on the market shall provide the following information from top to bottom in tabular form orderly shown at a conspicuous place of the outer package or container of the product. 3.1 Title of the “Nutrition Facts”. 3.2 ○ grams (or milliliters) per one serving (or per serving) and the number of servings contained in each package of the product. 3.3 “Per serving (or per one serving)”, “per 100 grams (or milliliters)” or “per serving (or per one serving)”, “daily percentage reference value”. 3.4 Contents of calories. 3.5 Contents of protein. 3.6 Contents of fats, saturated fats (or saturated fatty acids), and trans fats (or trans fatty acids). 3.7 Contents of carbohydrates and sugar. 3.8 Contents of sodium. 3.9 Conformed to the definition of nutrition claim of Article 2. Contents of other nutrients declared in the “Regulations on Nutrition Claim for Prepackaged Food Products”. Contents of other nutrients labeled voluntarily by the manufacturer. Each or total dietary fiber, each sugar, sugar alcohol labeled voluntarily by the manufacturer can be labeled behind carbohydrates item, and after sugar item. Cholesterol, other fatty acids can be labeled behind fat item, and after trans fats (fatty acids) item. Amino acids can be labeled behind protein item. If the vertical form can’t be fully presented, it can be labeled in horizontal continuous form. If multiple prepackaged food or tastes are commonly used in the same nutrient labeling, it can be combined. Nutrition labeling on surface areas smaller than 100 cm2 can be labeled those nutrition information sequentially in horizontal table form. 4. Caloric and nutritional content labeling for prepackaged foods on the market shall be labeled in Arabic numerals and processed under the following provisions: 4.1 Use “per one serving (or per serving)” and “per 100 grams (or milliliters)” for labeling, and the number of servings contained in each package of the product shall also be specified; or 4.2 Use “per one serving (or per serving)” and the provided “daily percentage of reference value” for labeling, and the number of servings contained in each package of the product shall also be specified. Labels shall also be specified the daily nutrient intake reference value if the daily nutrient intake reference value has been set (exempted from the prepackaged food surface areas smaller than 100 cm2). For products without a set daily nutrient intake reference value, the “*” symbol shall precede the daily percentage reference value line and clearly note “*Reference value not set.” Regarding the formatting of Clauses 1 and 2 in the preceding item shall refer to Appendix 1. Infant foods and shall be labeled according to the format of Clause 1 in the preceding item. Products in the form of tablets and capsules (excluding candy foods) shall be labeled according to the format of Clause 2 in the preceding item. 5. The weight (quantity or volume) per serving of the various packaged food products shall consider every times consumption derived from domestic dietary habits and prepackaged food product type. Food products in the form of tablets and capsules (excluding candy foods) shall be labeled as recommended amount (shall be an integer). 6. Measure units for prepackaged food nutrition labeling shall be labelled the following regulations: 6.1 Solid (semi-solid) shall be expressed in grams (g); liquid shall be expressed in milliliters (mL or ml). 6.2 Caloric value is expressed in kilocalories (Kcal or kcal). 6.3 Proteins, fats, saturated fats (fatty acids), and trans fats (fatty acids), total mono or polyunsaturated fats (fatty acids), carbohydrates, sugars, dietary fibers, and sugar alcohols are expressed in grams (g). 6.4 Sodium, cholesterols, and amino acids are expressed in milligrams (mg). 6.5 Vitamins and minerals units refer to Appendix 1. 6.6 Other nutritional values are expressed using the metric system or their common symbols. If product with nutrition claims requires re-hydration, the nutrition labeling must comply with the content (“per serving, per one serving” or “per 100 milliliters”) after re-hydration. If product without nutrition claims requires re-hydration, the nutrition labeling can be in according to the content before or after re-hydration. The re-hydration method shall be stated clearly shown at the outer package. 7. Daily caloric and other nutrient intake reference values shall be labeled according to Appendix 1. 8. The nutrient contents of energy, protein, fats, carbohydrate, sodium, saturated fats (fatty acids), trans fats (fatty acids) and sugars may be labeled as "0" if it meets the criteria in Appendix 2. 9. Data formatting of prepackaged food nutrition labeling units shall conform to the following regulations: 9.1 Each quantity, serving number, daily percentage reference value, caloric, protein, amino acid, fat, fatty acid, cholesterol, carbohydrate, sugar, sodium, dietary fiber, and other nutrients labeled voluntarily shall be labeled using whole integers or integers with one decimal point. The amount of caloric or nutrients per serving can be labeled using integers with two decimal points when the amount of caloric or nutrients per 100 grams (or milliliters) isn’t meet the criteria of labeling as "0". 9.2 The serving size (weight or capacity) can be labeled using integers with two decimal points when it is too small to present the real value if labeled using integers with one decimal points. 9.3 When an non-assembled prepackaged product with varied weight or its serving number is not divisible, the serving number can be labeled as “ This package contains (about) ○ serving(s)” after data formatting to whole integers. 9.4 Labels for vitamins and minerals shall not exceed three significant figures. 9.5 Data formatting shall refer to the Chinese National Standard CNS2925 “Practices for Designating Significant Places in Specific Limiting Values” or “Round half up” method. 10. The values on the nutritional labels of prepackaged foods must be derived from actual test analysis or calculations, and the range of allowable error shall meet the criteria in Appendix 3. If the characteristics of specific nutrient content of fermented food may change with time, the variation of the nutrients can be annotated. 11. The caloric calculation methods for nutritional labels of prepackaged foods shall conform to the following regulations: 11.1 Protein calories are calculated at 4 Kcal per gram. 11.2 Fat', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","nutrition-label","prepackaged-food"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1633","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:10.412Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
