insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-additive-standards', 'b54192dff90ac13216c3aba96391da6b917fe26005b27bf96c7f0b62e983c36d', '2026-06-25T13:02:10.646Z', true, 52857, 3868, 'data/knowledge/documents/tw-tfda-food-additive-standards.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Standards for Specification, Scope, Application and Limitation of Food Additives 【Update Date： 2018-06-19 】 unit：食品組 【Announced Date： 2008-11-20 】 【Amended Date： 2022-08-02 】 Article 1 The Standards are prescribed in accordance with the provisions of Article 18 of the Act Governing Food Sanitation. Article 2 The name, scope, application and limitation of food additives shall meet appendix 1. Not listed in the table shall not be used. Article 3 The specification of food additives shall meet appendix 2. Article 4 The Standards shall be implemented from the date of promulgation. The Standards amended on 19th June 2018 shall be implemented on 1st July 2019 of this Act. The Standards amended on 7th November 2019 shall be implemented on 1st July 2020 of this Act. The Standards amended on 11th August 2020 shall be implemented on 1st July 2022 of this Act. The Standards amended on 29th September 2020 shall be implemented on 1st January 2023 of this Act. The Standards amended on 22th February 2021 shall be implemented on 1st July 2022 of this Act. The Standards amended on 17th March 2021 shall be implemented on 1st July 2022 of this Act. The Standards amended on 23th June 2021 shall be implemented on 1st January 2024 of this Act. The Standards amended on 10th Mar 2022 shall be implemented on the date of promulgation, except that Appendix 1 “07. Food quality improvement, fermentation and food processing agents 07099 Nitrogen", Appendix 2 “07. Food quality improvement, fermentation and food processing agents § 07099 Nitrogen", Appendix 2 “08. Nutritional Additives § 08112 Lactoferrin" and Appendix 2 “16. Emulsifier § 16006 Diacetyl Tartaric Acid Esters of Mono- and Diglycerides" implemented on January 1, 2023. The Standards amended on 10th August 2023 shall be implemented on 1st January 2024 of this Act. Files Appendix II Standards for Scope Application and Limitation of Food Additives-20230810 (implemented in 20240101) Appendix I Standards for Scope Application and Limitation of Food Additives-20230810 (implemented in 20240101) Links Standards for Specification, Scope, Application and Limitation of Food Additives News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","food-additives","scope","limits","standards"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=308","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:10.646Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
