insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-nutrition-labeling-exemptions', '353a84e88e5f3dbe1795b400b0bfecd16f1b04c4b273fe182b3a301574685102', '2026-06-25T13:02:10.871Z', true, 46622, 3066, 'data/knowledge/documents/tw-tfda-nutrition-labeling-exemptions.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations on Prepackaged Food Products Exempted from the Nutrition Labeling 【Update Date： 2022-04-18 】 unit：食品組 【Announced Date： 2018-03-14 】 【Amended Date： 2018-03-14 】 1.This regulation is established under the provisions of Article 23 of the Act Governing Food Safety and Sanitation. 2.Nutrition labeling is not required for the following categories of prepackaged products without nutrition claims: (1)Drinking water, mineral water, and ice. (2)Fresh, refrigerated, and frozen fruits, vegetables, meat, poultry, eggs, liquid eggs and seafood that do not contain other ingredients. (3)Tea leaves, coffee, dried beans, wheats, and other herbs and flower, fruits, and seeds, used for brewing that do not contain other ingredients or food additives. (4)Spices and stewed spice packages used for flavoring. (5)Salt and salt substitutes. (6)The calories and nutrient contents in nutrition labeling of other foods may be labeled as "0" if they meet the criteria of the “Regulations on Nutrition Labeling for Prepackaged Food Products ". If a nutrition labeling is voluntarily used in above categories of products, it shall be handled in accordance with the provisions of Article 22 of the Act Governing Food Safety and Sanitation. 3.Prepackaged foods and food raw materials are not for sell to consumers are exempt from nutrition labeling. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","nutrition-label","exemptions","prepackaged-food"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3393","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:10.871Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.