insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-specific-fish-species-name-labeling', 'Labeling Requirements on Food Products that Use Specific Fish Species as Product Names', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3414', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'medium', '["food","fish","product-name","species-name","labeling"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-specific-fish-species-name-labeling', '631983f9f1ad7219c3fd19f2124b3e1f52dd5cde943200bee52aa7ea6193fb40', '2026-06-25T13:02:10.991Z', true, 52675, 5247, 'data/knowledge/documents/tw-tfda-specific-fish-species-name-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Labeling Requirements on Food Products that Use Specific Fish Species as Product Names 【Update Date： 2022-04-22 】 unit：食品組 【Announced Date： 2016-07-14 】 【Amended Date： 2016-07-14 】 Article1 According to Article 28 of the Act Governing Food Safety and Sanitation (hereinafter referred to as the “Act”), the labeling, promotion, and advertisement of foods may not be false, exaggerated or misleading. In addition, Article 7 of the Enforcement Rules of the Act Governing Food Safety and Sanitation stipulates that the product names shall conform to the nature thereof. Article2 Based on the data from the Fish Database of Taiwan, Fisheries Research Institute of the Council of Agriculture, and Biodiversity Research Center of the Academia Sinica, the fish species of the“Gadiformes (鱈形目)”can only be labeled as “cod”, including Gadus morhua(大西洋鱈), Gadus macrocephalus(大頭鱈，太平洋鱈), Gadus ogac(格陵蘭鱈), Gadus chalcogrammus(黃線狹鱈，阿拉斯加鱈), Melanogrammus aeglefinus(黑線鱈), Pollachius pollachiu(青鱈), Pollachius virens(綠青鱈), Merluccius productus(北太平洋無鬚鱈), Macruronus novaezelandiae(藍尖尾無鬚鱈), Urophycis tenuis(長鰭鱈) that are now circulated in Taiwan’s market. Article3 The commercial name “Patagonian toothfish (圓鱈)” is actually either “Dissostichus eleginoides”(小鱗犬牙南極魚) and “Dissostichus mawasoni”(鱗頭犬牙南極魚) (commonly known as “Chilean seabass(智利海鱸)” that are of the “Perciformes”(鱸形目);“Greenland Halibut(扁鱈) is in fact “Reinhardtius hippoglossoides”(馬舌鰈), Hippoglossus hippoglossus (庸鰈) and Hippoglossus stenolepis(狹鱗庸鰈) (commonly known as “halibut”(大比目魚) that are of the “Pleuronectiformes (鰈形目) ”. Article4 The local health bureaus are requested to actively provide guidance for the relevant businesses in their local jurisdictions. The fish species of the ‘’Gadiformes’’(鱈形目) can only be labeled as “cod”. Fish species not belonging to the’’Gadiformes” but labeled as “cod” shall be deemed to constitute mislabeling. However, considering that “Patagonian toothfish (圓鱈) and Greenland Halibut(扁鱈)” are the product names that are commonly used by the public, at this stage ,businesses should be advised to either label“Patagonian toothfish (圓鱈) and Greenland Halibut(扁鱈)”with their common names or label “Patagonian toothfish (圓鱈) and Greenland Halibut(扁鱈)”together with the name of the fish species. Regardless, such fish cannot be labeled as “cod”. From January 1, 2017 onwards, “Patagonian toothfish (圓鱈) and Greenland Halibut(扁鱈)”product have not been clearly labeled in accordance with the above requirements in such a way as to mislead consumers to believe it is“cod”, the food business will be deemed to have violated Article 28 of the Act and will be punished with a fine between NT$40,000 and NT$4,000,000; and the products shall be recalled and corrected before the deadline stipulated in Article 52 of the Act. Article5 In addition, if a specific fish species is used as the product name of a product, the ingredients of the product shall indeed contain said fish species that is claimed in the product name. If the ingredients do not contain the claimed fish species and instead species or seasonings are used to create the flavor of the claimed fish species, the words “flavor”/“taste” shall be indicated in the product name or an obvious place close to the product name. In the event that the labeling fails to meet the aforementioned requirements, it shall be deemed to have violated Article 28 of the Act Governing Food Safety and Sanitation and shall result in the punishments provided in Articles 45 and 52 of the Act. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","fish","product-name","species-name","labeling"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3414","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:10.991Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
