insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-allergen-labeling', '2829ab727c41cca224ab12823bf83dedcada5a9fa77c18269c5148e1907e015d', '2026-06-25T13:02:11.232Z', true, 399682, 1644, 'data/knowledge/documents/tw-tfda-food-allergen-labeling.md', 'Regulation of Food Allergen Labeling Article 1 This regulation is established under the provision of Subparagraph 10 of Paragraph 1 of Article 22 of the Act Governing Food Safety and Sanitation. Article 2 Prepackaged food products containing following substances which cause an allergic reaction in susceptible individuals shall be labeled with the warning information on the package: (1) Crustacea and products thereof. (2) Mango and products thereof. (3) Peanut and products thereof. (4) Milk, goat milk and products thereof, except lactitol derived from milk and goat milk. (5) Egg and products thereof. (6) Nuts and products thereof. (7) Sesame and products thereof. (8) Cereals containing gluten and products thereof, except glucose syrup, maltodextrin and alcohol produced from cereals. (9) Soybean and products thereof, except highly refined or purified soybean oil (fat), tocopherols and their deviation, phytosterols and phytosterol esters. (10) Fish and products thereof, except fish gelatine used as carrier for vitamin or carotenoid preparations; fish gelatine used as fining agent in alcohol. (11) The use of sulphites etc., at concentrations of 10 mg/kg or more in term of total SO 2 which are to be calculated for final products. Article 3 The warning information prescribed in Article 2 shall be labeled as either way: (1) Labeling on the package with the term of “This product contains ______”, “This product contains ______, unsuitable for susceptible individuals”, or other synonymous terms. (2)The product name claims ______ , label in this way, all the allergic substances of product should be included in the product name.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","allergen","prepackaged-food","warning-label"],"format":"pdf","page_count":1,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/tc/includes/GetFile.ashx?id=f636826556478322315","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:11.232Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
