insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-recommended-allergen-labeling', 'Regulations Governing Food Allergen Labeling on the Recommended Labeling Allergens', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3407', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'high', '["food","allergen","recommended-allergen","cross-contamination","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-recommended-allergen-labeling', 'd07d3b35f521dbef23978e30e157dedfbbde3a897704bfe8440d0a5fdf552898', '2026-06-25T13:02:11.561Z', true, 48116, 3694, 'data/knowledge/documents/tw-tfda-recommended-allergen-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations Governing Food Allergen Labeling on the Recommended Labeling Allergens 【Update Date： 2022-04-22 】 unit：食品組 【Announced Date： 2018-08-21 】 【Amended Date： 2018-08-21 】 Article 1 For prepackaged foods, food allergen labeling is required for the products that contain any of the following 11 allergens as an ingredient or food additive, regulated under Point 2 of the Regulation of Food Allergen Labeling: Crustacean shellfish, mango, peanuts, sesame seeds, milk and goat milk, eggs, tree nuts, gluten-containing cereals, soybeans, fish, and sulphite as the residue sulphur dioxide for 10 or more milligrams per kilogram of food. Besides the mandatory labeling allergens, food allergen labeling is also recommended for the products that contain any of the following allergens as an ingredient or food additive: (1) Cephalopods and cephalopod products: cuttlefish (calamari), neritic squid (small squid and squid), octopus, squid, etc. and relevant products such as takoyaki and dried shredded squid. (2) Spiral shells and Spiral shell products thereof: escargot, mussel, clam, oyster, scallop, mytilus, meretrix lusoria, abalone, etc. and relevant products such as scallop sauce, scallop candy and spiral shell sauce. (3) Seeds and seed products: Sunflower seed, melon seed, etc. However, sunflower seed oil, which is highly refined or purified from sunflower seeds, is not included. (4) Kiwis and kiwi products thereof: Kiwi jam, dried kiwi, etc. Article2 Control measures shall be set in place to prevent food from cross contamination in the production process. If there is a risk of a food product being affected by allergen cross-contamination, such as using the same plant, equipment or production line for food containing allergenic ingredients or additives, the following statement of precautionary allergen labeling is suggested: “ The plant, equipment or production line used to produce the product is also used to process○○” or the synonymous terms. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","allergen","recommended-allergen","cross-contamination","prepackaged-food"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3407","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:11.561Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
