insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-allergen-labeling-consumer-notice', '48867cfc5502f5521bd4bf4f5cb933e483d07e289e1a6b63e47c187cbb995da7', '2026-06-25T13:02:12.432Z', true, 165614, 2858, 'data/knowledge/documents/tw-tfda-food-allergen-labeling-consumer-notice.md', '包裝食品過敏原，不漏看，安心吃 - 本署新聞 - 公告資訊 - 衛生福利部食品藥物管理署 --> 跳到主要內容區塊 English ::: 回首頁 網站導覽 English 雙語辭彙 常見問答 為民服務信箱 衛生局專區 RSS 大 中 小 關鍵字搜尋 站台 站外 搜尋 進階搜尋 熱門關鍵字： 食品添加物 營養標示 非登不可 基因改造 選單按鈕 全站搜尋 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 機關介紹 署長介紹 業務介紹 使命、願景與目標 機關聯絡資訊 本署諮議或審議任務編組委員名單 業務聯絡資訊 署徽設計說明 業務專區 食品 藥品 醫療器材 化粧品 區管理中心 管制藥品 實驗室認證 製藥工廠管理(GMP/GDP) 研究檢驗 企劃及科技管理 邊境查驗專區 通報及安全監視專區 法規資訊 組織及處務類 藥品、醫療器材及化粧品類 食品類法令規章 藥廠GMP相關法規 實驗室認證管理 GTP相關法規 規費與其他類 修法專區 檢驗類 管制藥品類 科技計畫執行作業相關法令及規定 便民服務 食品藥物開放資料平臺(OPEN DATA) 為民服務信箱 下載專區 廣告申請 常見問答 問卷及民調 訂閱電子報 政風園地 文宣品下載專區 旁聽專區 請託關說登錄專區 違規食品、藥物、化粧品廣告查詢 簽審系統排除錯單人員資料.pdf 出版品 新出版品消息 電子報專區 圖書 期刊 歷史資料 出版品訂購 食品藥物管理署年報 政府資訊公開 法規資訊 施政計畫及施政績效 業務統計及研究報告 預算、決算書、會計月報及會計制度 補助案件及相關規定 書面之公共工程及採購契約 出國報告 現代化食品藥物國家級實驗大樓暨行政及訓練大樓興建計畫 行政指導有關文書 營業及非營業基金執行成果 本署涉及全民利益之任務編組委員利益自我揭露與涉及食品標準訂定之會議紀錄 內部控制 遊說資訊專區 勞基法例假七休一例外規定專區 檔案應用 個人化服務 加入會員 人民申請案件 藥證查詢系統 校園食材 農藥殘留容許量申請案查詢 為民服務信箱 English 常見問答 網站導覽 衛生局專區 --> 雙語辭彙 --> English --> 資訊安全策略 著作權聲明 隱私權保護宣告 網站資料開放宣告 --> ::: 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 ::: 目前位置： 首頁 > 公告資訊 > 本署新聞 20220727_google+服務已停止 --> 訂閱或取消電子報 --> 包裝食品過敏原，不漏看，安心吃 | 發布日期：2023-06-22 | 維護日期：2023-06-22 發布單位：食品組 為保障過敏體質消費者食的安心，衛生福利部(下稱衛福部)已要求包裝食品業者 加強揭露食品過敏原標示訊息。包裝食品含有甲殼類、芒果、花生、牛奶羊奶、蛋、堅果類、芝麻、含麩質之穀物、大豆、魚類等10項及其製品，以及使用亞硫酸鹽類等終產品其二氧化硫殘留量每公斤10毫克以上者，均須在產品的容器或外包裝上顯著標示含有致過敏性內容物名稱之相關醒語資訊。 另外， 針對烏賊等頭足類、田螺等螺貝類 、葵花籽等種子類 、奇異果等4項及其製品，衛福部也建議業者標示相關醒語資訊。如食品生產製程中未使用，但共用廠房、設備或生產管線有處理致生過敏之內容物，建議標示載明 「本產品生產製程廠房，其設備或生產管線有處理○○」或等同意義字樣。 食品藥物管理署提醒有過敏體質的 消費者，看清楚包裝上標示「本產品含有○○」、「本產品含有○○，不適合對其過敏體質者食用」或等同意義字樣，確保食用安心，健康不過敏。 資訊內容對您是否有幫助： 極其有幫助 非常有幫助 有一定幫助 有點幫助 沒有幫助 驗證碼： 寄發驗證碼至信箱： (每次寄發驗證碼需間隔60秒) 送出評分 回上一頁 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 機關介紹 署長介紹 業務介紹 使命、願景與目標 機關聯絡資訊 本署諮議或審議任務編組委員名單 業務聯絡資訊 署徽設計說明 業務專區 食品 藥品 醫療器材 化粧品 區管理中心 管制藥品 實驗室認證 製藥工廠管理(GMP/GDP) 研究檢驗 企劃及科技管理 邊境查驗專區 通報及安全監視專區 法規資訊 組織及處務類 藥品、醫療器材及化粧品類 食品類法令規章 藥廠GMP相關法規 實驗室認證管理 GTP相關法規 規費與其他類 修法專區 檢驗類 管制藥品類 科技計畫執行作業相關法令及規定 便民服務 食品藥物開放資料平臺(OPEN DATA) 為民服務信箱 下載專區 廣告申請 常見問答 問卷及民調 訂閱電子報 政風園地 文宣品下載專區 旁聽專區 請託關說登錄專區 違規食品、藥物、化粧品廣告查詢 簽審系統排除錯單人員資料.pdf 出版品 新出版品消息 電子報專區 圖書 期刊 歷史資料 出版品訂購 食品藥物管理署年報 政府資訊公開 法規資訊 施政計畫及施政績效 業務統計及研究報告 預算、決算書、會計月報及會計制度 補助案件及相關規定 書面之公共工程及採購契約 出國報告 現代化食品藥物國家級實驗大樓暨行政及訓練大樓興建計畫 行政指導有關文書 營業及非營業基金執行成果 本署涉及全民利益之任務編組委員利益自我揭露與涉及食品標準訂定之會議紀錄 內部控制 遊說資訊專區 勞基法例假七休一例外規定專區 檔案應用 個人化服務 加入會員 人民申請案件 藥證查詢系統 校園食材 農藥殘留容許量申請案查詢 Facebook粉絲團 食用玩家 睡睡平安 化粧品安全 藥博士 正藥說 ::: 資訊安全策略 | 隱私權保護宣告 | 著作權聲明 | 網站資料開放宣告 地址 115021 臺北市南港區研究院路一段130巷109號 交通位置圖 電話(02)2787-8000 (總機人員服務時間：公告上班日上午8:00-下午17:30) 諮詢服務專線 (02)2787-8200 (服務時間：人事行政總處公告上班日8:00-18:00) 1919食安資訊專線 tel:1919(需付費，市話：依一般市內電話費率，行動電話：3.6元/分或0.06元/秒計費) 業務聯絡資訊 衛生福利部食品藥物管理署 © 2016版權所有 建議最佳瀏覽解析度為1024x768或以上 衛生福利部食品藥物管理署 © 2016版權所有 建議最佳瀏覽解析度為1024x768或以上 --> 瀏覽人次：501162431', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","allergen","prepackaged-food","warning-label","traditional-chinese"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/tc/newsContent.aspx?cid=4&id=28867","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:12.432Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract,