insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-front-of-package-nutrition-labeling', 'Guidelines for Front of Package Nutrition Labeling of Food Products', 'https://www.fda.gov.tw/tc/includes/GetFile.ashx?id=f637862485315287265', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'guideline', 'medium', '["food","front-of-package","nutrition-label","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-front-of-package-nutrition-labeling', '33fbdc6597f03dde24617761eb24e15bf96ad48a6126efb33f46402400e46d2f', '2026-06-25T13:02:12.636Z', true, 853656, 6370, 'data/knowledge/documents/tw-tfda-front-of-package-nutrition-labeling.md', 'Guidelines for Front of Package Nutrition Labeling of Food Products Promulgated on November 15, 2017 I. Introduction In recent years, many countries have encouraged business to voluntarily label simple and succinct nutrition information diagrams, in addition to the nutrition labeling, on the packaging of food products. This is intended to provide consumers with quickly and easy-to-understand nutrition information symbols, so that consumers are able to select the products that meet their needs most. In order to encourage food businesses to implement Front of Package Nutrition Labeling (FoP), this guidance is thus formulated for food businesses to follow. II. Scope This Guideline applies to all packaged food products, except for special dietary foods. For those that are exempted from nutrition labeling, if food businesses of such food products voluntarily have FoP, they are not required to comply with the Regulations on Nutrition Labeling for Prepackaged Food Products. However, the correctness of labeled values shall be assured. III. Definitions 1.The terms used in this guideline are defined as follows : (1) “Front of Package Nutrition Labeling (FoP)”: the labeling of calories, nutrients content, and percentage of daily reference value in the form of a diagram on the front package of food products. (2) “Per serving”: the weight (or volume) of per serving of the various prepackaged food products, which is identical to Article 5 1 of Regulations on Nutritional Labeling for Prepackaged Food Products. (3) “Percentage of daily reference value”: the daily calories and other nutrient intake reference values of prepackaged food products, which is identical to 1 The weight (quantity or volume) per serving of the various packaged food products shall consider every time consumption derived from domestic dietary habits and prepackaged food product type. Food products in the form of tablets and capsules (excluding candy foods) per serving shall be labeled as recommended amount (shall be an integer). Article 7 2 of Regulations on Nutrition Labeling for Prepackaged Food Products. IV. Principles for FoP nutrition labeling of prepackaged food products 1. Location of the label: Any place on the front of package (main display side) of the product. 2. Items of labeling, to include any of the following: (1) Calories; (2) Calories, Saturated Fat, Sugar, Sodium; or (3) Calories, Saturated Fat, Sugar, Sodium, and maximum of two voluntarily claimed nutrients 3 . 3. Format of labeling: (1) Refer to Regulations on Nutrition Labeling for Prepackaged Food Products; use “per serving” as the labeling unit. (2) Provide " content for every nutrient per serving ”and its “percentage of daily reference value”. 4. The order of the labeling content should be listed from top to bottom in accordingly as: (1) Unit (per serving); (2) Calories or nutrient names ; (3) Content; (4) Percentage of daily reference value (%Daily value, %DV). For nutrients without a set daily reference value, the percentage of daily reference value will be exempted. 5. Figure of labeling: (1) The figure design of the FoP is not restricted. Nevertheless, the size of each figure shall be identical. (2) The figure shall be presented in two colors, that is, white color with another 2 Daily caloric and other nutrient intake reference values shall be labeled according to Attachment 2 of Regulations on Nutrition Labeling for Prepackaged Food Products. 3 The two of other nutrients labeled voluntarily shall be declared in nutrition labeling according Regulations on Nutrition Labeling for Prepackaged Food Products . color, such as black and white, blue and white, or red and white. And, the colors of FoP shall be distinguishable from the package color of the food product. (3) The samples of FoP are provided in attachment. 6. Characters size: The size of characters shall conform to Article 19 of the Enforcement Rules of the Act Governing Food Safety and Sanitation 4 . Attachment 1. Sample of FoP 1: Calorie label only (1) The FoP meaning: Per serving is 120g of the product, there are 500 calories, which is 25% of the daily diet. (2) Sample of FoP: %: the percentage of daily reference value %: the percentage of daily reference value 2. Sample of FoP 2: Calories, saturated fat, sugar and sodium are labeled. (1) The FoP meaning: Per serving is 120g of the product, there are 500 calories, which is 25% of the daily diet; there are 18g of saturated fat, which is 100% of the daily diet; there are 15g of sugar (there is without set nutrient intake 4 The length and width of the characters marked on the labels shall not be less than two millimeters. However, where the area of the largest surface of a package is less than 80 square centimeters, the length and width of characters for all items other than the name of the product, the company name, and expiry date, may be less than two millimeters. Per serving (120 g) Per serving (120g) Calorie Calories 500 Calories Calories Calories 500 Calories daily reference value, so there is no percentage of daily reference value); there are 1000mg of sodium, which is 50% of the daily diet. (2) Sample of FoP: %: the percentage of daily reference value %: the percentage of daily reference value 3. Sample of FoP 3: Calories, saturated fat, sugar, sodium, and two of other nutrients labeled voluntarily (such as dietary fiber and calcium) are labeled. (1) The FoP meaning: Per serving is 120g of the product, there are 500 calories, which is 25% of the daily diet; there are 18g of saturated fat, which is 100% of the daily diet; there are 15g of sugar (there is without set nutrient intake of daily reference value, so there is no percentage reference value); there are 1000mg of sodium, which is 50% of the daily diet; there are 5g of dietary fiber, which is 25% of the daily diet; and there are 240mg of calcium, which is 20% of the daily diet. Per serving (120g) Calories 500 Saturated Fat 18g Sugar 15g Sodium 1000mg Calories 500 Calories Saturated Fat 18g Sugar 15g Sodium 1000mg Per serving (120g) (2) Sample of FoP : %: the percentage of daily reference value %: the percentage of daily reference value Per serving (120g) Calories 500 Saturated Fat 18g Sugar 15g Sodium 1000mg Dietary Fiber 5g Calcium 240mg Per serving (120g) Saturated Fat 18g Sugar 15g Sodium 1000mg Dietary Fiber 5g Calcium 240mg Calories 500 Calories', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","front-of-package","nutrition-label","prepackaged-food"],"format":"pdf","page_count":5,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/tc/includes/GetFile.ashx?id=f637862485315287265","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:12.636Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-small-prepackaged-food-labeling', 'Regulations Governing the Labeling of Small Prepackaged Food', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3408', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'medium', '["food","small-package","qr-code","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-small-prepackaged-food-labeling', '72dc295120e86a6226746dbf5e5ad736a4e978f76c5b002ef338890286ac3612', '2026-06-25T13:02:12.787Z', true, 47404, 3125, 'data/knowledge/documents/tw-tfda-small-prepackaged-food-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations Governing the Labeling of Small Prepackaged Food 【Update Date： 2022-04-22 】 unit：食品組 【Announced Date： 2021-09-01 】 【Amended Date： 2021-09-01 】 Article 1 The Regulations are prescribed in accordance with Article 23 of the Act Governing Food Safety and Sanitation. Article 2 Prepackaged food where the largest surface area is less than 20 cm² and being sold in the market may choose one of the following labeling methods: 1. Only the following items shall be labeled on the outer packaging of the product： (1) product name; (2) expiry date; (3) name and telephone number of the responsible domestic company; (4) country of origin and the country of origin of raw materials designated by the central competent authority in a public announcement; (5) reminder information such as allergens. 2. In addition to the product name and expiry date shall be labeled on the outer packaging of the product, the labeling items according to Article 22 Paragraph1 Subparagraphs 2 to 6 and 8 to 10 of the Act Governing Food Safety and Sanitation, shall be disclosed electronically on the outer packaging of the product by using "QR Code" or other electronic means. The reminder information shall also be accompanied on the top or bottom of the electronic labeling as follows: "Scan here to get product information" or equivalent words. Files Regulations Governing the Labeling of Small Prepackaged Food News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","small-package","qr-code","prepackaged-food"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3408","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:12.787Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-bulk-food-labeling', 'Regulations on Bulk Food Labeling', 'https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3398', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'medium', '["food","bulk-food","chinese-label"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-bulk-food-labeling', '7e404b721df626f77dfaaad29bc74def0a3d806158fd4254cc528a19a2405baa', '2026-06-25T13:02:12.895Z', true, 47945, 3955, 'data/knowledge/documents/tw-tfda-bulk-food-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations on Bulk Food Labeling 【Update Date： 2022-04-18 】 unit：食品組 【Announced Date： 2020-09-17 】 【Amended Date： 2020-09-17 】 Article 1 These regulations are prescribed in accordance with the provisions of Paragraph 2 of Article 25 of the Act Governing Food Safety and Sanitation. Article 2 This regulation is applicable to the Bulk Food of defined in Article 20 of the Enforcement Rules of the Act Governing Food Safety and Sanitation. Article 3 Food business operators with company registration or business registration, which sell the Bulk Food shall label the product name and the country of origin. Except for foods for baking (roasting) and dealing with ready-to-eat foods on-site. Article 4 Food business operators without company registration or business registration, which sell the following Bulk Food shall label the country of origin of the product: Fresh, chilled, frozen, dehydrated, dried, crushed, ground, simple cutting Peanuts, Red beans, Mung beans, Black beans, Soybeans, Buckwheat, Barley, Quinoa, Sesame, Foxtail millet, Garlic, Shiitake, Tea, Red dates, Wolfberry, Hang Chrysanthemum, Chicken, Pork, Mutton ( lamb and goat meat) and Beef. Article 5 Food business operators sell the Bulk Food products that contain beef, pork and other edible parts of cattle and pig shall label the beef, pork and edible parts of cattle and pig of raw material of the country. The country of origin of beef, pork and other edible partsof cattle and pig shall be the country where the cattles and pigs are slaughtered. The beef and edible parts of cattle mentioned in the above paragraph do not include milk, fat of cattle. Article 6 The Bulk Food labeling as provisioned by these Regulations shall be labelled in Chinese and in the form of cards, mark (label) or notice boards which in turn are either posted, hung, erected (inserted), stuck or utilized in other ways which are clearly visible. The vendors who choose to label the products with the mark (label) shall make sure the front of the remainder is larger than 2 millimeter in length and width. Those who choose to label the products with other means of communication shall make sure the front of the remainder is larger than 2 centimeters in length and width. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","bulk-food","chinese-label"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3398","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:12.895Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
