insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-business-use-intact-package-labeling', 'a68cd4757ebbd4481e76150220e663b21ea7a2cc53fcce335aedda0a005dc066', '2026-06-25T15:09:13.960Z', false, 47055, 2999, 'data/knowledge/documents/tw-tfda-food-business-use-intact-package-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Principles for Managing the Labeling of Foods (including Raw Materials) with Intact Package for Business Use 【Update Date： 2022-04-22 】 unit：食品組 【Announced Date： 2013-12-06 】 【Amended Date： 2013-12-06 】 Article 1 The labeling of prepackaged foods (including raw materials) for business use, whether manufactured locally or imported, shall be completely labeled in accordance with Article 22 of the Act Governing Food Safety and Sanitation. Interpretation letters DOH No. 0910065723, DOH No. 0910053196 and DOH No. 0910037302, issued by the former Department of Health of the Executive Yuan on October 15, 2002, September 3, 2002, and December 6, 2013, respectively, are no longer applicable. Article 2 Imported foods (including raw materials) that need to be repackaged, sub-packaged or further processed, the complete labeling in Chinese on the external packaging may not be required if there is identifiable original label or information for managing the products. For all other situations, Chinese labeling shall be completed prior to the sale (object including food factories, catering industry, or consumers) of the products. (Interpretation letter TFDA No. 1029009423 issued on December 6, 2013; Interpretation letter TFDA No. 1021351991 issued on January 20, 2014) News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","business-use","raw-materials","intact-package","repackaging","chinese-label"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3411","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T15:09:13.960Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, fr