insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-import-inspection-exemptions', '309074a3e09e8ff900a50ab8a060474d7cdc3dcd3602a77e3d1b082ab07f54c3', '2026-06-25T15:09:13.960Z', false, 51441, 4659, 'data/knowledge/documents/tw-tfda-food-import-inspection-exemptions.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Requirements for exemption from inspection application for import of food and related products and the applicable custom code 【Update Date： 2022-02-10 】 unit：食品組 【Announced Date： 2022-02-10 】 【Amended Date： 2022-02-10 】 Issue Date: April 16, 2019 Issue No.: MOHW Shou Shi Zi No. 1081300310 Subject: Setting “Requirements for exemption from inspection application for import of food and related products and the applicable custom code,” effective from May 1, 2019. Basis: Act Governing Food Safety and Sanitation, Paragraph 3, Article 30 Announcement: Import of products which should apply for inspection according to the Act Governing Food Safety and Sanitation Paragraph 1, Article 30 that are not for sale, and the amount of money and quantity of which meet the following conditions can be exempt from applying for inspection; the custom code should filled in the import permit number column on the import declaration form as well and compliance with Act Governing Food Safety and Sanitation, Paragraph 3, Article 30 declared when they are imported: 1.When the importer is an embassy in the ROC or a person with diplomatic immunity and importing for personal use, the code is DH000000000001. The quota of value and quantity of “import of food and related products” and “food containers and utensils” for personal use shall meet No.2 and NO.4. of this Announcement, respectively. 2.For import of food and related products (excluding food in tablet or capsule form) of every single item on the import declaration form with value less than 1,000 US dollars and weight of less than 6 kilograms for personal use, and import of food in tablet or capsule form for personal use, for which up to 12 bottles/boxes/bags for each type is allowed, no more than 36 in total, the code is DH000000000002. 3.For import of food and related products compliant with Customs Act Article 52 for re-export customs duty exemption, the code is DH000000000003. When customs duty needs to be paid for changing use after importing, release documents should be inspected before change of use. 4.For import of food containers and utensils of every single item on the import declaration form for personal use with value less than 1,000 US dollars and the quantity of fewer than 4 of each item , or with value of more than 1,000 US dollars and the quantity of individual one, the code is DH000000000005. 5.“Every single item on the import declaration” indicates the total amount of imported food products with same product name, ingredients, brand, manufacturer and origin, including all batch number, manufacturing date (expire date) or the total amount of packaging specifications from the same product name. 6.The custom code in this announcement does not apply to the following items: (1)Food additives and spices (2)Meat, tissue, organs, derivatives of beef cattle imported from BSE-infected countries, and products containing the products mentioned above. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","import-inspection","inspection-exemption","custom-code","personal-use"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3371","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T15:09:13.960Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
