insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-compound-food-additive-import-documents', '1d96d566eed0b19172264c455cd07c9ae61114e8959f54b95d8ed412ec104feb', '2026-06-25T17:40:27.672Z', false, 170386, 3137, 'data/knowledge/documents/tw-tfda-compound-food-additive-import-documents.md', '輸入複方食品添加物應檢附產品成分報告及官方衛生證明 - 本署新聞 - 公告資訊 - 衛生福利部食品藥物管理署 --> 跳到主要內容區塊 English ::: 回首頁 網站導覽 English 雙語辭彙 常見問答 為民服務信箱 衛生局專區 RSS 大 中 小 關鍵字搜尋 站台 站外 搜尋 進階搜尋 熱門關鍵字： 食品添加物 營養標示 非登不可 基因改造 選單按鈕 全站搜尋 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 機關介紹 署長介紹 業務介紹 使命、願景與目標 機關聯絡資訊 本署諮議或審議任務編組委員名單 業務聯絡資訊 署徽設計說明 業務專區 食品 藥品 醫療器材 化粧品 區管理中心 管制藥品 實驗室認證 製藥工廠管理(GMP/GDP) 研究檢驗 企劃及科技管理 邊境查驗專區 通報及安全監視專區 法規資訊 組織及處務類 藥品、醫療器材及化粧品類 食品類法令規章 藥廠GMP相關法規 實驗室認證管理 GTP相關法規 規費與其他類 修法專區 檢驗類 管制藥品類 科技計畫執行作業相關法令及規定 便民服務 食品藥物開放資料平臺(OPEN DATA) 為民服務信箱 下載專區 廣告申請 常見問答 問卷及民調 訂閱電子報 政風園地 文宣品下載專區 旁聽專區 請託關說登錄專區 違規食品、藥物、化粧品廣告查詢 簽審系統排除錯單人員資料.pdf 出版品 新出版品消息 電子報專區 圖書 期刊 歷史資料 出版品訂購 食品藥物管理署年報 政府資訊公開 法規資訊 施政計畫及施政績效 業務統計及研究報告 預算、決算書、會計月報及會計制度 補助案件及相關規定 書面之公共工程及採購契約 出國報告 現代化食品藥物國家級實驗大樓暨行政及訓練大樓興建計畫 行政指導有關文書 營業及非營業基金執行成果 本署涉及全民利益之任務編組委員利益自我揭露與涉及食品標準訂定之會議紀錄 內部控制 遊說資訊專區 勞基法例假七休一例外規定專區 檔案應用 個人化服務 加入會員 人民申請案件 藥證查詢系統 校園食材 農藥殘留容許量申請案查詢 為民服務信箱 English 常見問答 網站導覽 衛生局專區 --> 雙語辭彙 --> English --> 資訊安全策略 著作權聲明 隱私權保護宣告 網站資料開放宣告 --> ::: 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 ::: 目前位置： 首頁 > 公告資訊 > 本署新聞 20220727_google+服務已停止 --> 訂閱或取消電子報 --> 輸入複方食品添加物應檢附產品成分報告及官方衛生證明 | 發布日期：2015-12-28 | 維護日期：2015-12-28 發布單位：食品組 為強化輸入複方食品添加物產品之管理，自104年12月10日起，依據食品安全衛生管理法(下稱食安法)第35條第4項之規定， 食品業者輸入複方食品添加物(香料除外)，應檢附原產國之製造廠商或負責廠商出具之產品成分報告及輸出國之官方衛生證明，供各級主管機關查核。衛生福利部 於104年12 月 28 日發布解釋令，就應檢附之 「產品成分報告」及「官方衛生證明」進行解釋，供業者遵循。 「產品成分報告」應載明個別原料名稱，如屬食品添加物者，其名稱應為食品添加物使用範圍及限量暨規格標準所定之品名，或中央主管機關公告之通用名稱。「官方衛生證明」係指由出產國出具產品之「合法製售工廠之證明」、出產國或負責廠商國出具「產品衛生證明」、「產品自由銷售證明」或相同性質之證明文件。食品業者輸入複方食品添加物時，應依前述規定檢附該 2 項報告及文件 ，始得輸入。 如於國內查獲已輸入之複方食品添加物，輸入時未檢附該2項報告及文件，可依食安法第48條命其限期改正，屆期不改正者，處3萬元以上300萬元以下罰鍰。 針對複方食品添加物之管理，食藥署依食安法規定，已逐步落實包括訂定准用食品添加物品項、使用範圍、限量及規格標準，強制所有食品添加物產品辦理登錄，輸入食品添加物應辦理輸入查驗，食品添加物製造、加工、調配及輸入業者應建立追溯追蹤系統，及實施自主檢驗。今實施輸入複方食品添加物檢附 「產品成分報告」，可於產品通關時掌握產品所含確切成分，另要求檢附「官方衛生證明」，可保障產品來源之衛生安全。 檔案下載 相關FAQ 資訊內容對您是否有幫助： 極其有幫助 非常有幫助 有一定幫助 有點幫助 沒有幫助 驗證碼： 寄發驗證碼至信箱： (每次寄發驗證碼需間隔60秒) 送出評分 回上一頁 公告資訊 本署公告 本署新聞 維護公告 活動訊息 預告法規沿革區 食藥膨風廣告專區 食藥闢謠專區 國內衛生局新聞 國外消費紅綠燈 本署徵才 重大政策 科技計畫 招標資訊 新聞API服務 國際與兩岸會議及研討會 機關介紹 署長介紹 業務介紹 使命、願景與目標 機關聯絡資訊 本署諮議或審議任務編組委員名單 業務聯絡資訊 署徽設計說明 業務專區 食品 藥品 醫療器材 化粧品 區管理中心 管制藥品 實驗室認證 製藥工廠管理(GMP/GDP) 研究檢驗 企劃及科技管理 邊境查驗專區 通報及安全監視專區 法規資訊 組織及處務類 藥品、醫療器材及化粧品類 食品類法令規章 藥廠GMP相關法規 實驗室認證管理 GTP相關法規 規費與其他類 修法專區 檢驗類 管制藥品類 科技計畫執行作業相關法令及規定 便民服務 食品藥物開放資料平臺(OPEN DATA) 為民服務信箱 下載專區 廣告申請 常見問答 問卷及民調 訂閱電子報 政風園地 文宣品下載專區 旁聽專區 請託關說登錄專區 違規食品、藥物、化粧品廣告查詢 簽審系統排除錯單人員資料.pdf 出版品 新出版品消息 電子報專區 圖書 期刊 歷史資料 出版品訂購 食品藥物管理署年報 政府資訊公開 法規資訊 施政計畫及施政績效 業務統計及研究報告 預算、決算書、會計月報及會計制度 補助案件及相關規定 書面之公共工程及採購契約 出國報告 現代化食品藥物國家級實驗大樓暨行政及訓練大樓興建計畫 行政指導有關文書 營業及非營業基金執行成果 本署涉及全民利益之任務編組委員利益自我揭露與涉及食品標準訂定之會議紀錄 內部控制 遊說資訊專區 勞基法例假七休一例外規定專區 檔案應用 個人化服務 加入會員 人民申請案件 藥證查詢系統 校園食材 農藥殘留容許量申請案查詢 Facebook粉絲團 食用玩家 睡睡平安 化粧品安全 藥博士 正藥說 ::: 資訊安全策略 | 隱私權保護宣告 | 著作權聲明 | 網站資料開放宣告 地址 115021 臺北市南港區研究院路一段130巷109號 交通位置圖 電話(02)2787-8000 (總機人員服務時間：公告上班日上午8:00-下午17:30) 諮詢服務專線 (02)2787-8200 (服務時間：人事行政總處公告上班日8:00-18:00) 1919食安資訊專線 tel:1919(需付費，市話：依一般市內電話費率，行動電話：3.6元/分或0.06元/秒計費) 業務聯絡資訊 衛生福利部食品藥物管理署 © 2016版權所有 建議最佳瀏覽解析度為1024x768或以上 衛生福利部食品藥物管理署 © 2016版權所有 建議最佳瀏覽解析度為1024x768或以上 --> 瀏覽人次：501195081', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","food-additives","compound-food-additive","composition-report","official-health-certificate","import-documents"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/tc/newsContent.aspx?cid=4&id=19405","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T17:40:27.672Z","cache