insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-imported-food-inspection-regulations', 'Regulations of Inspection of Imported Foods and Related Products', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1356', 'Taiwan Food and Drug Administration', 'TW', 'food_import', 'regulation', 'high', '["food","import-inspection","border-inspection","documents","ccc-code","tfda","import-declaration"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-imported-food-inspection-regulations', '9744a763fa7a46539146447f69239be907ed08f9468e9b122794cc200b0d1dc7', '2026-06-25T16:17:17.358Z', false, 144517, 47559, 'data/knowledge/documents/tw-tfda-imported-food-inspection-regulations.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations of Inspection of Imported Foods and Related Products 【Update Date： 2014-04-03 】 unit：區管理中心 【Announced Date： 2019-06-18 】 【Amended Date： 2019-06-18 】 DOH Food No. 0900074645 Promulgated, December 14, 2001. DOH Food No. 0960403095 Amended and promulgated on June 22, 2007; these regulations are effective as on July 1, 2007. DOH Food No. 0991304411 Amended and promulgated on December 30, 2010 and the title was amended to “Regulations of Inspection of Imported Foods and Related Products”. DOH Food No. 1021300813 Partial amended and promulgated on April 1, 2013 MOHW Food No. 1022051463 Amended and promulgated on January 27, 2014. MOHW Food No. 1042000518 Partial amended and promulgated on June 24, 2015 MOHW Food No. 1072004519 Partial amended and promulgated on October 18, 2018 MOHW Food No. 1082002676 Partial amended and promulgated on June 10, 2019 Chapter 1 General Principles Article 1 The regulations are duly enacted in accordance with Paragraph 3 of Article 33 of the Act Governing Food safety and Sanitation (hereinafter “the Act”). Article 2 The terms herein are defined as follows: 1. Obligatory Inspection Applicant: Business who imports food, food additives, food utensils, food packaging, or food cleansers, and other related products (hereinafter "products"). 2. Inspection Authority: The central competent authority or its commissioned organization, institution, corporation or group. 3. Verification: The inspection authority check product name, specification and package of products applied for inspection. And exam its appearance, shape, properties, indication and other examination in accordance with laws and regulations. 4. Analysis: The inspection authority take samples and send to laboratories to conduct sensory, chemical, biological, or physical examination and experiment. Chapter 2 Application for Inspection Article 3 The Obligatory Inspection Applicant or Representative shall file an application for inspection to the inspection authority at the port of entry within fifteen (15) days prior to the entry date. If the application be filed by representative, an identification document for the representative shall be provided. If the representative is an individual, he/she shall submit his/her certificate of identification. If any entity, who undertakes application and declaration agent as business, shall submit its broker license, business license and identification documents to the inspection authority for future reference. Article 4 Obligatory Inspection Applicants shall submit the following documents and papers to the inspection authority for inspection: 1. An application form for inspection. 2. A declaration form of product information. 3. A photocopy of application for import declaration. 4. Necessary documents and papers required by the Food and Drug Administration, Ministry of Health and Welfare (hereinafter as “TFDA”). In accordance with Article 32 of the Act, the inspection authority may require Obligatory Inspection Applicants to provide other necessary documents and papers. The Obligatory Inspection Applicants shall not evade, obstruct or refuse. The forms of inspection in Paragraph 1 may be by electronic files or any other manner required by TFDA. Article 5 (Discard) Article 6 Products for inspection application in the same shipment shall have the same import declaration、CCC code、product name、ingredients、brand、producer and country of origin. If the import products were live, fresh or chilled fish, prawn, crab, shellfish, or belong to the same class from four classes of mollusk, the inspection authority may permit the applicant to apply different products in one inspection application. Article 7 For any Obligatory Inspection Applicant belong to one of the following situations, the competent authority shall dismiss his/her application for inspection: 1. Applicants fail to apply an inspection application pursuant to Article 4 or the preceding article of this regulation. 2. Incomplete inspection application form, product information declaration form or other related form, and fail to make correction within a limited period. 3. Repeated application for inspection for products mentioned in the previous article that have already been selected for batch inspection in accordance with Subparagraph 2, Paragraph 1, Article 8. Chapter 3 Inspection Procedures Article 8 The inspection authority may proceed product inspection with the following measures: 1. Batch-by-batch inspection: Inspect each submitted batch of product by on-site verification and sampling analysis basis. 2. Randomly-selected batch inspection: Randomly select each submitted batch of product by following inspection rate, and inspect the chosen product by on-site verification and sampling analysis. (1)Regular randomly-selected batch inspection: The inspection is performed based on a 2-10% inspection rate. (2)Reinforced randomly-selected batch inspection: The inspection is performed based on a 20-50% inspection rate. 3. Batch-by-batch verification: On-site inspect each submitted batch of product. 4. Certification inspection: Certificate Document inspection for an excellent industry which is registered by an entente or agreement between the health and safety competent authority of Taiwan and the exporting country. 5. Oversee inspection: For specific products, each submitted batch of product shall be inspected by on-site verification and sampling analysis. And the inspection rate is not changed by the inspection result. For those products not be selected in randomly-selected batch inspection, the inspection authorize may exam extra by on-site verification and sampling analysis; For products be designated for batch-by-batch verification, the inspection authorize may exam extra by sampling analysis. Article 9 Products applied for inspection that belong to one of the following situations shall be inspected on a batch-by-batch basis: 1. Products proved to cause harm to humans according to domestic and foreign product safety information or scientific evidence. 2. Products designated for batch-by-batch inspection are listed in the TFDA annual inspection plan (hereinafter as “inspection plan”) for imported products. 3. Products with the same origin and commodity classification code of the Republic of China (hereafter referred to as ‘CCC Code’) as preceding batches of products belonging to reinforced randomly-selected batch inspections of the same obligatory inspection applicant, and whose inspection results do not conform to regulations. 4. For products applied to oversee inspection and fail the inspection two batches in a row. 5. The inspection authority determines that it is necessary to carry out the inspection on a batch-by-batch basis. Prior to the completion of the batch-by-batch inspection procedures for the preceding batch, the batches re-applied for inspection to such batch of products shall be subject to inspection on a batch-by-batch basis. Article 10 Products applied for inspection that belong to one of the following situations shall be inspected on a reinforced randomly-selected batch basis: 1. Products designated for reinforced randomly-selected batch inspection are listed in the inspection plan for imported products. 2. Products applied for inspection originally belong to batch-by-batch inspection, and the same obligatory inspection applicant has imported five consecutive batches of such products from the same origin and CCC Code, and whose laboratory examination results conform to regulations. However, if the preceding batch before th', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","import-inspection","border-inspection","documents","ccc-code","tfda","import-declaration"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1356","extra_fetched_urls":["https://law.moj.gov.tw/ENG/LawClass/LawAll.aspx?pcode=L0040017"],"cache_days":30,"cache_expires_at":"2026-07-25T16:17:17.358Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
