insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-systematic-inspection-imported-food', 'a1f6fed5bd8bb3cb184345e5f0d7f5e23f7cfbfbe120c9aa3f7823377af35bbf', '2026-06-25T16:17:17.358Z', false, 59881, 7153, 'data/knowledge/documents/tw-tfda-systematic-inspection-imported-food.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations for Systematic Inspection of Imported Food 【Update Date： 2019-09-26 】 unit：食品組 【Announced Date： 2014-02-11 】 【Amended Date： 2019-09-26 】 Regulations for Systematic Inspection of Imported Food Promulgated on February 11, 2014 Amended on October 17, 2014 Amended on August 4, 2017 Amended on September 17, 2018 Amended on September 26, 2019 Article 1 These Regulations are established in accordance with the provisions of Paragraph 2 of Article 35 of the Act Governing Food Safety and Sanitation (hereinafter referred to as “Act”). Article 2 The terms used in these Regulations are defined as follows: 1. “Systematic inspection” means inspecting the food safety management system and the supervisory measures taken by the governments of the exporting country (territory). 2. “Inspection authority” means the Food and Drug Administration, Ministry of Health and Welfare. 3. “Document review” means reviewing the documentation relating to the food safety management system in the exporting country(territory) provided by the governmental authority of the exporting country (territory). 4. “On-site inspection” means the inspection authority designates inspectors to conduct the systematic inspection of the food safety management system in the exporting country (territory). Article 3 The scope of products subject to systematic inspection is outlined in the attachment. Article 4 To perform systematic inspection and evaluate the equivalance of the food safety management system of the exporting country (territory), the exporting country (territory) shall apply to the inspection authority with documents for approval of import of the product described in the above paragraph. Inspection authority shall conduct the documents review. If required, on-site inspection can be conducted following the document review. The inspection authority may make the following decision based on the result of systematic inspection: 1. Market access approval for products of the establishments designated by competent authority of the exporting country(territory). 2. Market access approval for products of the establishments which have been inspected and qualified by the inspection authority. 3. Disapproval of the application for market access. If necessary, inspection authority shall request the exporting country (territory) to provide the documents within the designated period when performing the pre-said document review. Products which are subjected to the scope of this regulation, are not conforming to the paragraph 2 of this Article shall not apply for import inspection at border, except for the exemption according to Article 7 or according to the bilateral agreement with the exporting country(territory). Article 5 For any exporting country(territory)that has been systematically inspected and been approved to import or that is exempted from systematic inspection in accordance with the provisions of Article 7, in case of any of the following, the inspection authority may request document review or on-site inspection to confirm the equivalence of the management system of the exporting country (territory). 1. Significant changes of food safety management system or the supervisory measures of the exporting country (territory). 2. Occurrence of significant food sanitation and safety incidents in the exporting country (territory). 3. Significant violation of the food or related product from the exporting country (territory) found by the inspection authority or other importing country (territory). 4. Any exporting country (territory) that is exempted from systematic inspection in accordance with the provisions of Article 7 or that has been finished systematically inspected more than three years, deemed necessary to conduct documents review or on-site inspection by the inspection authority. 5. Food or related products which from the exporting country (territory) were determined as jeopardizing food safety. Article 6 If the results of on-site inspection are non-compliant, the exporting country (territory) may be required to submit corrective actions, to the inspection authority for review before deadline. If required, on-site re-inspection might be performed again to verify the effectiveness of the corrective actions. The expenses of on-site inspection shall be borne by the exporting country (territory) in the following circumstances: 1. Re-inspection of the paragraph 1 of this Article. 2. Application for expanding designated establishments in the case of the subparagraph 2 of paragraph 2 of Article 4. 3. Re-application for systematic inspection in the case of the subparagraph 3 of paragraph 2 of Article 4. If necessary, the i nspection authority will request the exporting country(to bear the expenses of on site inspection other than the circumstances of the paragraph 2 of this Article. Article 7 Products, subjected to the scope of this regulation, had existed import records before promulgation of these Regulation might be exempted from the systematic inspection. Article 8 These Regulations shall be implemented from the date of promulgation unless other specified. Files Regulations for Systematic Inspection of Imported Food(2019-9-26)(PDF) Links Law&Regulations Database of The Republic of China 【En】Application Procedures for Importing Beef from Bovine Spongiform Encephalopathy (BSE) - infected Countries Imported food Digital Management System (for systematic inspection) News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","import-inspection","systematic-inspection","document-review","onsite-inspection","exporting-country"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1607","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T16:17:17.358Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-shellfish-hs0307-health-certificate', 'Shellfish HS 0307 health certificate requirement', 'https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3095', 'Taiwan Food and Drug Administration', 'TW', 'food_import', 'notice', 'medium', '["food","shellfish","hs-0307","health-certificate","harvest-area","border-inspection"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-shellfish-hs0307-health-certificate', '5c4c4f5125e1f08f8188aa63ad7f2837be0a4cc36021362f5c1176444b3d294a', '2026-06-25T16:17:17.358Z', false, 46598, 2512, 'data/knowledge/documents/tw-tfda-shellfish-hs0307-health-certificate.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Shellfish should be accompanied with a health certificate which imported for human consumption 【Update Date： 2017-10-31 】 unit：食品組 【Announced Date： 2017-10-31 】 【Amended Date： 2017-10-31 】 MOHW Food No. 1061302493 Promulgated, October 31, 2017. In accordance of Regulation of Inspection of Imported Foods and Related Products of Subparagraph 4 of Paragraph 1 of Article 4, Shellfish listed in 0307 of the Harmonised System Codes (HS Code) imported for human consumption shall be accompanied with a health certificate that includes the information of the catching or harvest area and issued by the official competent authority of the exporting country, effective from January 1, 2018. Files Shellfish should be accompanied with a health certificate which imported for human consumption News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","shellfish","hs-0307","health-certificate","harvest-area","border-inspection"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3095","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T16:17:17.358Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-food-business-registration-importers', 'Regulations Governing the Registration of Food Business', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1681', 'Taiwan Food and Drug Administration', 'TW', 'food_import', 'regulation', 'medium', '["food","importer-registration","food-business","product-liability-insurance","storage","repackaging"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-business-registration-importers', '4798f195285036a7bde243cf853aee940400f846db3d616a1c2f712b158df4d5', '2026-06-25T16:17:17.358Z', false, 60702, 7296, 'data/knowledge/documents/tw-tfda-food-business-registration-importers.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations Governing the Registration of Food Business Operators 【Update Date： 2026-01-05 】 unit：食品組 【Announced Date： 2013-09-03 】 【Amended Date： 2026-01-05 】 Article 1 This Regulation is laid down in accordance with Paragraph 4 of Article 8 of the Act Governing Food Safety and Sanitation (hereinafter referred to as "the Act"). Article 2 This Regulation is applicable to the categories and scale of food business operators as promulgated by central competent authority in accordance with Paragraph 3 of Article 8 of the Act. Article 3 Food business operators shall apply to the municipal or county (city) competent authorities in writing or by way of electronic verification for the purposes of registration, amendment, revocation or termination of registration and are required to regularly confirm the registration details. Food business operators shall appoint personnel (hereinafter the “Filing Personnel”) to be responsible for the registration and filing under the previous paragraph. Article 4 Various categories of food business operators shall register the following information: 1. For manufacturing and processing business operators: (1) Filing Personnel''s basic information; (2) Food business operators'' basic information; (3) Details of product liability insurance; (4) Details of factory registration; (5) Details of factory or manufacturing site; (6) Status of commission or commissioned processing; (7) Information on the products to be manufactured and processed. (8) Storage place’s basic information; (9) Other descriptions relating to manufacture activities. 2. For catering business operators: (1) Filing Personnel''s basic information; (2) Food business operators'' basic information; (3) Details of product liability insurance; (4) Basic information about the factory or the restaurant; (5) Storage place’s basic information; (6) Information of chain stores; (7) Other descriptions relating to food and beverage activities. 3. For import business operators: (1) Filing Personnel''s basic information; (2) Food business operators'' basic information; (3) Details of product liability insurance; (4) Category of products to be imported; (5) Information on the products to be imported. (6) Storage place’s basic information; (7) Repackaging and other descriptions relating to importing activities. 4. For retail business operators: (1) Filing Personnel''s basic information; (2) Food business operators'' basic information; (3) Information on the products to be sold . (4) Storage place’s basic information; (5) Other descriptions relating to sales activities. 5. For logistics (1) Filing Personnel''s basic information; (2) Food business operators'' basic information; (3) Storage place’s basic information; (4) Transportation vehicle’s basic information; (5) Other descriptions relating to logistics activities. Food business operators operate in different categories simultaneously must complete separate registration in respect of such category. Information mentioned in Item 7, Subparagraph 1, Paragraph 1 shall meet the requirements in Appendix 1. Information mentioned in Item 5, Subparagraph 3, Paragraph 1 shall meet the requirements in Appendix 2. Information mentioned in Item 3, Subparagraph 4, Paragraph 1 shall meet the requirements in Appendix 3. Article 5 The municipality or county (city) competent authority shall order food business operators to correct their application within a specified time period when they fail to comply with the format or content as prescribed by the central competent authority. Should such business operators fail to correct before designated deadline, their applications may be rejected. Registration number shall be issued by municipality or county (city) competent authority once the application is completed. Article 6 In accordance with Article 41 of the Act, the municipality or county (city) competent authorities may enter food business operators'' premises to verify and request for related documents to verify information registered. Food business operators shall not evade, impede or refuse such examination. Article 7 Any amendment must be registered by food business operators within thirty days of the occurrence of such event. After food business operators complete the registration, it shall verify the information registered in every year. Article 8 Food business operators shall apply to the municipal or county (city) competent authorities for the termination of business or the revocation of their company registration, business registration or factory registration. The municipality or county (city) competent authorities shall revoke its registration. The municipality or county (city) competent authorities shall revoke such registration in absence of such application. Article 9 The municipality or county (city) competent authorities shall revoke the registration number issued to non-food business operators. Article 10 The Regulations shall take effect from the date of promulgation, except for Item 3, Subparagraph 1; Item 3, Subparagraph 2; and Item 3, Subparagraph 3, Paragraph 1, Article 4, which were amended and promulgated on January 5, 2026, shall take effect on July 1, 2026. Files Appendix 1：Food business operators shall register the following information on the products to be manufactured and processed Appendix 2：Food business operators shall register the following information on the products to be imported Appendix 3：Food business operators shall register the following information on the products to be sold Links Law&Regulations Database of The Republic of China News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-26","authority":"Taiwan Food and Drug Administration","domain":"food_import","tags":["food","importer-registration","food-business","product-liability-insurance","storage","repackaging"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1681","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T16:17:17.358Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
