insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-trade-ccc-import-export-regulations', 'Import and Export Regulations by CCC Code', 'https://fbfh.trade.gov.tw/fh/indexE.jsp', 'International Trade Administration, MOEA', 'TW', 'trade_controls', 'database', 'high', '["ccc-code","import-regulation","export-regulation","permit","trade-controls"]'::jsonb, 7, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-trade-ccc-import-export-regulations', '3a475d0f91d1fb612822a132d9ac4a1ba5fd6f95bb6b7aec4980b7bb7708bd7b', '2026-06-25T14:44:25.986Z', false, 2290, 2290, 'data/knowledge/documents/tw-trade-ccc-import-export-regulations.md', 'Official Taiwan International Trade Administration/MOEA database page for Classification of Commodities and Regulations. The English interface is titled Import and Export Regulations and supports searching by commodity code, commodity code range, or imported file. It accepts HS code inputs from 2 to 6 digits and CCC code inputs under the Standard Classification of Commodities of the Republic of China up to 10 digits, with examples including 01, 2001, 740729, 0203120000, and 2207101010. The page also supports commodity-description keyword search, such as fish, bovine animals, or chemical, and regulation-code search for import or export regulation types. The form refers to Import Regulation codes and Export Regulation codes, with examples including numeric codes and alphanumeric codes such as 111, 401, 272, C01, and MW0. The page provides download areas for import/export regulation information and an Importation of Mainland China products section. It explains that where EX is appended after a CCC number, only goods conforming to the corresponding Chinese and English commodity description are opened for import. It also notes that where Mainland China product import special regulation codes such as MXX or NXX are listed, the goods must satisfy both general import regulations and those special provisions before import is allowed. The user workflow is to identify a commodity by HS or CCC number, confirm whether an import regulation code, export regulation code, permit, inspection, or agency restriction appears, and then map the result back to the responsible agency and shipment documents. This makes the page a primary routing source before preparing invoices, packing lists, origin evidence, TFDA documents, SHTC checks, or customs entries. This source is used by LabelPass for CCC-code based routing, import/export permit signals, trade-control screening, and search terms such as CCC code, HS code, import regulation code, export regulation code, regulation codes, commodity description, controlled goods, permit code, regulatory agency, and trade controls. It is a query database rather than a static legal text, so LabelPass stores this manual extract to preserve the official page semantics for search and review evidence while the live URL remains the authority.', '{"source_registry_version":"2026-06-26","authority":"International Trade Administration, MOEA","domain":"trade_controls","tags":["ccc-code","import-regulation","export-regulation","permit","trade-controls"],"format":"manual","page_count":null,"parse_error":null,"fetched_url":"https://fbfh.trade.gov.tw/fh/indexE.jsp","extra_fetched_urls":[],"cache_days":7,"cache_expires_at":"2026-07-02T14:44:25.986Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-customs-tariff-database-download', 'GC453 Tariff Database Download', 'https://portal.sw.nat.gov.tw/APGQ/GC453', 'Customs Administration / CPT Single Window', 'TW', 'customs', 'tariff_database', 'high', '["hs-code","ccc-code","tariff","customs","import-export"]'::jsonb, 7, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-customs-tariff-database-download', '0eea087b9d2d707180562eacfd052152e4b7bfb6a5e9d2acb9f7ba7b88bbd719', '2026-06-25T14:44:25.986Z', false, 2165, 2097, 'data/knowledge/documents/tw-customs-tariff-database-download.md', 'Official CPT Single Window / Customs Administration page GC453 Tariff Database Download. The page is a browser-oriented official download page for Taiwan tariff and CCC-code reference data. It identifies the CCC CODE last modification date and presents official download options for tariff and commodity-code work. Listed resources include Tariff Schedule files in spreadsheet, PDF, and open-document formats; CCC Code and Description of Goods files in text and PDF formats; chapter-by-chapter tariff materials; Application for Import Goods Advance Tariff Rulings files in document, PDF, and open-document formats; and Tariff No. and Description of Goods files in text and PDF formats. The page is relevant when a product team needs to confirm the Taiwan customs statistical classification, compare HS candidates, download the current tariff schedule, or prepare an advance classification ruling before import. The tariff schedule and CCC goods-description files support screening for duty rate, import/export controls, TFDA routing, BSMI routing, SHTC routing, and other agency rules that depend on commodity classification. Advance tariff ruling materials are important when product composition, use, kit status, or mixed-material goods make the final CCC code uncertain. LabelPass uses this source to connect HS code and Taiwan CCC code searches with tariff classification, customs statistical code review, duty-rate routing, and import/export regulatory screening. Practical search terms mapped to this source include GC453, tariff database download, tariff schedule, CCC CODE, CCC code description of goods, tariff number, tariff no., customs tariff, HS code, Standard Classification of Commodities of the Republic of China, advance tariff ruling application, import goods advance tariff ruling, 관세율표, 대만 CCC 코드, 세번, 稅則號列, 貨品分類號列, 海關編碼, 進口貨物稅則預先審核, tariff no. and description of goods, and customs import tariff. Automated HTTP access may return a browser-only message, so LabelPass keeps this manual extract from the official page while retaining the live official URL for audit and refresh.', '{"source_registry_version":"2026-06-26","authority":"Customs Administration / CPT Single Window","domain":"customs","tags":["hs-code","ccc-code","tariff","customs","import-export"],"format":"manual","page_count":null,"parse_error":null,"fetched_url":"https://portal.sw.nat.gov.tw/APGQ/GC453","extra_fetched_urls":[],"cache_days":7,"cache_expires_at":"2026-07-02T14:44:25.986Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
