insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-customs-origin-importers', '0da863dde7ec359160adca40ebc2470a66fff2854adc699e8f83b880ebd6ca15', '2026-06-25T13:02:17.038Z', true, 99286, 4906, 'data/knowledge/documents/tw-customs-origin-importers.md', 'Keelung Customs Calls on Traders to Meet Country of Origin Labeling Requirements-Keelung Customs X message close ::: Skip to main content Site Map Contact us 中文版 font size A A A :: Popular search： x About KLC Duties and Jurisdiction Administrative Functions Features of Keelung Customs Vision of Keelung Customs Director of Keelung Customs Location Harbor Building Traveler Enquiry Hotlines Arrival Depature Anti-Money Laundering Customs Declaration Forms VAT Refund Mini-Three-Links Import/Export Import Cargo Clearance Advance Tariff Classification Rulings Duty Assessment of Imported Used Vehicles Country of Origin Marking for Exports Customs Treatment of Inconsistent Declarations Maritime Express Consignments Clearance Free Trade Zone MCC Export Cargo Clearance Enforcement Laws and Regulations Non Intrusive Inspection Trader Sealing Trade Control Anti-smuggling Operations Container Inspection and Monitoring FAQ Import/Export Clearance Maritime Express Consignments Clearance Imported Used Vehicles Bonded Warehouse&Temporary Storage Facilities Intellectual Property Rights Protection Convenience Service Time Frames for Applications Processing Glossary of Customs Terms SOP for Auditing AEOGs Forms Download On - Line Application Services and Amenities Home > Other information > Hot news > Keelung Customs Calls on Traders to Meet Country o... ::: Other information Hot news Travelers Links Privacy Open Information Interactive Zone Information Security Statistics Graphs and Tables ::: X Forward friends 「*」Required field * Sender(Required) * Recipient(Required) * Content of email(Required) * Verification code(Required) Regenerate verification code Keelung Customs Calls on Traders to Meet Country of Origin Labeling Requirements Keelung Customs (KLC) stated that the origin of import commodities shall be displayed correctly; namely, false or misleading labels are forbidden. If such situation happens, traders should apply for re-labeling so that the commodities could be imported, and may get further punishment by the International Trade Administration, Ministry of Economic Affairs or other relevant agencies. KLC further explained that according to current import regulations, imports such as footwear, ceramic tiles, non-medical masks and certain textiles like garments, towels, socks and bedding are label-required. As to other commodities that are not label-required, the country of origin mustn’t be false or misleading if they are labeled. Below are some examples of misleading labels that we have found recently: 1. Using recycled cartons or other products’ wrapping that caused inconsistency as to the country of origin. 2. Marking the country, place, company, address, phone number, website address or trademark, etc. which has nothing to do with the origin, while not identifying the name of the domestic importer, agent or distributor. For example, Vietnam carpets with the name and address of Taiwan manufacturer. In order not to cause confusion on country of origin to the public, KLC emphasized again that traders shall confirm the origin of commodities and label correctly prior to importation for smooth clearance and to avoid penalties. For more information, please contact Import Division, KLC at 02-24202951 ext. 2210. Last updated：2024-05-22 Click times：2478 Open About KLC Duties and Jurisdiction Administrative Functions Features of Keelung Customs Vision of Keelung Customs Director of Keelung Customs Location Harbor Building Traveler Enquiry Hotlines Arrival Depature Anti-Money Laundering Customs Declaration Forms VAT Refund Mini-Three-Links Import/Export Import Cargo Clearance Advance Tariff Classification Rulings Duty Assessment of Imported Used Vehicles Country of Origin Marking for Exports Customs Treatment of Inconsistent Declarations Maritime Express Consignments Clearance Free Trade Zone MCC Export Cargo Clearance Enforcement Laws and Regulations Non Intrusive Inspection Trader Sealing Trade Control Anti-smuggling Operations Container Inspection and Monitoring FAQ Import/Export Clearance Maritime Express Consignments Clearance Imported Used Vehicles Bonded Warehouse&Temporary Storage Facilities Intellectual Property Rights Protection Convenience Service Time Frames for Applications Processing Glossary of Customs Terms SOP for Auditing AEOGs Forms Download On - Line Application Services and Amenities ::: Privacy Open Information Information Security Browsing peoplKeelung Customs Office of Customs Administration，Ministry of Finance Address：No. 6， Gangxi St， Keelung City， Taiwan ， ROC ( Location ) 🌏 Zip Code：20041 Domestic：TEL(02)-2420-2951 ；FAX (02)-2426-3324 Overseas：TEL 886-2-2420-2951；FAX 886-2-2426-3224 Office Hours：[H]UTC+8 AM 08:30 to PM 12:00 ; PM 01:00 to PM 05:00 on Monday to Friday Service Counter：AM 08:30 to PM 17:00 Non-Stop Service Through The Lunch Hour Best viewed at 1024 x 768 resolution. Last updated:2026-06-18', '{"source_registry_version":"2026-06-26","authority":"Taiwan Customs Administration","domain":"customs","tags":["customs","origin","misleading-label"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://web.customs.gov.tw/ekeelung/singlehtml/1444?cntId=9d9cf376a43c481faef23b3f584f782c","extra_fetched_urls":[],"cache_days":14,"cache_expires_at":"2026-07-09T13:02:17.038Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadat