insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('global-unece-ghs-rev11', 'd003b83f5a695efbc362bf8b65d814289c4fa04e74e877a92a31c6f747ab4762', '2026-06-25T13:56:16.130Z', false, 2431, 2431, 'data/knowledge/documents/global-unece-ghs-rev11.md', 'Official UNECE index for the Globally Harmonized System of Classification and Labelling of Chemicals, eleventh revised edition, 2025. The source page routes to the free electronic edition and to language downloads including the English PDF file GHS Rev11e.pdf. Official document citation: ST/SG/AC.10/30/Rev.11. The GHS, also known as the Purple Book, is the global baseline used by many jurisdictions for chemical hazard classification and hazard communication. It supports regulatory checks for substance and mixture classification, physical hazards, health hazards, environmental hazards, signal words, hazard pictograms, hazard statements, precautionary statements, product identifiers, supplier identification, label elements, and safety data sheet terminology. Rev. 11 takes account of amendments adopted by the UN Committee of Experts on the Transport of Dangerous Goods and on the Globally Harmonized System of Classification and Labelling of Chemicals in December 2024. Search anchors for this source include GHS, UN GHS, Purple Book, Globally Harmonized System, chemical classification, labelling of chemicals, SDS, safety data sheet, hazard communication, CLP alignment, OSHA HazCom alignment, pictograms, signal word, Danger, Warning, H statements, P statements, aerosols, chemicals under pressure, skin sensitization, non-animal methods, global warming potential, simple asphyxiants, Annex 11, precautionary statement rationalization, and ST/SG/AC.10/30/Rev.11. Additional retrieval anchors include classification criteria, flammable gases, flammable aerosols, flammable liquids, oxidizing gases, oxidizing liquids, oxidizing solids, explosives, self-reactive substances, pyrophoric liquids, pyrophoric solids, self-heating substances, water-reactive substances, organic peroxides, corrosive to metals, desensitized explosives, acute toxicity, skin corrosion, serious eye damage, respiratory sensitization, germ cell mutagenicity, carcinogenicity, reproductive toxicity, specific target organ toxicity single exposure, specific target organ toxicity repeated exposure, aspiration hazard, hazardous to the aquatic environment, hazardous to the ozone layer, and hazardous by contributing to global warming. This cached text is an official-source routing and retrieval note for environments where direct automated HTTP capture requires an interactive browser challenge; the legal reference remains the UNECE page and PDF.', '{"source_registry_version":"2026-06-26","authority":"United Nations Economic Commission for Europe","domain":"chemical_labeling","tags":["ghs","chemical-labeling","sds","hazard-communication","rev11","2025"],"format":"manual","page_count":null,"parse_error":null,"fetched_url":"https://unece.org/transport/dangerous-goods/ghs-rev11-2025","extra_fetched_urls":[],"cache_days":90,"cache_expires_at":"2026-09-23T13:56:16.130Z","cache_status":"fresh","browser_capture_path":"data/knowledge/browser-captures/global-unece-ghs-rev11-blocked.txt","screenshot_path":"data/knowledge/browser-captures/global-unece-ghs-rev11-blocked.png"}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
