insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('global-unece-ghs-rev11-pdf', '486b2ad4eff864354c0090c77729393da3fbcae2c56b06b7661517067c8dabd5', '2026-06-25T13:56:16.130Z', false, 2258, 2258, 'data/knowledge/documents/global-unece-ghs-rev11-pdf.md', 'Official UNECE English PDF for the Globally Harmonized System of Classification and Labelling of Chemicals, eleventh revised edition, 2025. File name: GHS Rev11e.pdf. Official document citation: ST/SG/AC.10/30/Rev.11. Publication metadata identifies it as a United Nations publication issued by the United Nations Economic Commission for Europe, with ISBN 978-92-1-003273-5 and PDF ISBN 978-92-1-003274-2. The English PDF is the authoritative source to retrieve when the system needs detailed evidence for GHS chemical classification and labelling rules. It should be used for chemical product review, hazard class identification, category terminology, signal word checks, pictogram checks, hazard statement checks, precautionary statement checks, supplier and product identifier checks, and safety data sheet terminology. Rev. 11 includes update anchors for aerosols and chemicals under pressure, skin sensitization classification using non-animal methods, substances and mixtures that are hazardous by contributing to global warming, rationalized precautionary statements, and Annex 11 guidance on simple asphyxiants. Operational aliases include UN GHS Rev.11, GHS 2025, Purple Book 2025, ST/SG/AC.10/30/Rev.11, hazard communication, chemical labelling, SDS, safety data sheet, pictogram, signal word, H statement, P statement, acute toxicity, skin corrosion, eye damage, carcinogenicity, reproductive toxicity, aquatic toxicity, ozone layer, global warming, aerosol, chemical under pressure, and simple asphyxiant. Detailed search anchors include label element, product identifier, supplier identification, supplemental information, hazard class, hazard category, mixture classification, bridging principle, cut-off value, concentration limit, precautionary pictogram, transport pictogram, skin sensitizer, respiratory sensitizer, mutagenicity, aspiration toxicity, metal corrosion, oxidizer, flammable solid, self-heating, pyrophoric, organic peroxide, desensitized explosive, combustible dust, and safety data sheet section terminology. This cached text is a retrieval note and search anchor for the official PDF in environments where direct automated PDF capture requires an interactive browser challenge; the legal reference remains the UNECE PDF URL.', '{"source_registry_version":"2026-06-26","authority":"United Nations Economic Commission for Europe","domain":"chemical_labeling","tags":["ghs","hazard-statements","precautionary-statements","pictograms","rev11","2025"],"format":"manual","page_count":null,"parse_error":null,"fetched_url":"https://unece.org/sites/default/files/2025-09/GHS%20Rev11e.pdf","extra_fetched_urls":[],"cache_days":180,"cache_expires_at":"2026-12-22T13:56:16.130Z","cache_status":"fresh","browser_capture_path":"data/knowledge/browser-captures/global-unece-ghs-rev11-pdf-blocked.txt","screenshot_path":"data/knowledge/browser-captures/global-unece-ghs-rev11-pdf-blocked.png"}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
