insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('eu-cosing-cosmetic-ingredients', 'a9c86b54634d008d7f7049263712aebfe29b8d6ac75096481e5f747133a6ec59', '2026-06-25T13:06:03.322Z', true, 95398, 4977, 'data/knowledge/documents/eu-cosing-cosmetic-ingredients.md', 'Cosmetic ingredient database - Internal Market, Industry, Entrepreneurship and SMEs Skip to main content en Select your language Close EU official languages bg български es español cs čeština da dansk de Deutsch et eesti el ελληνικά en English fr français ga Gaeilge hr hrvatski it italiano lv latviešu lt lietuvių hu magyar mt Malti nl Nederlands pl polski pt português ro română sk slovenčina sl slovenščina fi suomi sv svenska Other languages uk yкраїнська Search Search Internal Market, Industry, Entrepreneurship and SMEs Menu Close Menu Back Previous items Next items Home Single market Single market strategy Single market for goods Single market for services The Chief Economist & Business Intelligence Unit Internal Market Emergency and Resilience Act Single market simplification Single Market Programme (SMP) Public procurement The Single Market Enforcement Taskforce Single digital gateway See all Industry Advanced Manufacturing European industrial strategy Cluster policy Industrial alliances Sustainability Transition pathways International activities See all Entrepreneurship and SMEs Learn and plan SME fundamentals SME-friendly business conditions Growing and scaling as an SME Funding and support Challenges and resilience Continuity and exit See all Access to finance Policy areas European Competitiveness Fund InvestEU Data and surveys - SAFE Access to Finance portal See all Sectors Automotive industry Biotechnology Chemicals Construction sector Cosmetics Cultural and Creative Industries Electrical and Electronic Engineering Industries (EEI) The Agri-food Industrial Ecosystem Legal metrology Maritime industries Mechanical engineering Postal services Pressure equipment and gas appliances Proximity and social economy ecosystem Raw materials, metals, minerals and forest-based industries Toys Textiles Ecosystem – TCLF (Textiles, clothing, leather and footwear) industries See all Tools and databases Home … Sectors Cosmetics Cosmetic ingredient database Cosmetic ingredient database CosIng – Glossary of ingredients Common cosmetic ingredient names for labelling which have been compiled and updated by the Commission. CosIng is the European Commission database for information on cosmetic substances and ingredients contained in the Cosmetics Regulation (EC) No 1223/2009 of the European Parliament and of the Council Cosmetics Directive 76/768/EEC (cosmetics directive), as amended Glossary of common ingredient names for the purpose of labelling cosmetic products placed on the market (as established by Decision (EU) 2019/701 of 5 April 2019) Opinions on cosmetic ingredients of the Scientific Committee for Consumer Safety ( list of SCCS opinions ) CAS, ELINCS or EINECS numbers can be searched for in CosIng. The database includes all data since the adoption of the Cosmetics Directive in 1976. Current data is listed as ''active'', while historical data is listed as ''not active''. References to scientific opinions of the scientific committee on consumer safety are restricted to those published on the internet. You can find more information about INCI-names in the Personal Care Products Council website . Please note that CosIng database has informative purpose and no legal value. Search in the CosIng database Important notice Please note that ingredient assigned with an INCI name that appears in the inventory section of CosIng does not mean it is to be used in cosmetic products nor approved for such use. Concerning ingredients used in cosmetic products as colorants, preservatives and UV filters, only those authorised in Annexes IV, V, respectively VI to Cosmetic Regulation No 1223/2009 are listed in CosIng CosIng may also list ingredients known to be used in medicinal products. If, due to such ingredients, a product restores, corrects, or modifies physiological functions by exerting a pharmacological, immunological or metabolic action, the product shall be qualified as a medicinal product. However, products that, while having an effect on the human body, do not significantly affect the metabolism and thus do not strictly modify the way in which it functions, may be qualified as cosmetic products. The qualification of a product is to be decided by the national competent authorities, under the supervision of the courts, on a case-by-case basis, taking into account all the characteristics of the product. In addition, the use of any ingredient in cosmetic products must be supported by a safety assessment of the product. Internal Market, Industry, Entrepreneurship and SMEs This site is managed by: Directorate-General for Internal Market, Industry, Entrepreneurship and SMEs X Facebook Instagram Youtube Newsletter Contact us Contact our DG About us Our department Jobs at the European Commission Vacancies at this department Follow the European Commission Mastodon LinkedIn Bluesky Facebook Youtube Other Contact us Report an IT vulnerability Languages on our websites Cookies Privacy policy Legal notice Accessibility', '{"source_registry_version":"2026-06-26","authority":"European Commission","domain":"terminology","tags":["cosing","inci","cosmetic-ingredients","substances"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://single-market-economy.ec.europa.eu/sectors/cosmetics/cosmetic-ingredient-database_en","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:06:03.322Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('eu-dual-use-regulation-2021-821', 'EU Dual-Use Regulation 2021/821', 'https://publications.europa.eu/resource/celex/32021R0821.ENG', 'European Union / EUR-Lex', 'EU', 'export_control', 'law', 'high', '["dual-use","export-control","cyber-surveillance","sensitive-technology"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('eu-dual-use-regulation-2021-821', 'ad3e6c91e5dbdaeb3aaa56b0c7403f9817b76d5a1b55c6b29ef495a5c1858360', '2026-06-25T13:02:39.722Z', true, 5914063, 698971, 'data/knowledge/documents/eu-dual-use-regulation-2021-821.md', 'L_2021206EN.01000101.xml 11.6.2021 EN Official Journal of the European Union L 206/1 REGULATION (EU) 2021/821 OF THE EUROPEAN PARLIAMENT AND OF THE COUNCIL of 20 May 2021 setting up a Union regime for the control of exports, brokering, technical assistance, transit and transfer of dual-use items (recast) THE EUROPEAN PARLIAMENT AND THE COUNCIL OF THE EUROPEAN UNION, Having regard to the Treaty on the Functioning of the European Union, and in particular Article 207(2) thereof, Having regard to the proposal from the European Commission, After transmission of the draft legislative act to the national parliaments, Acting in accordance with the ordinary legislative procedure ( 1 ) , Whereas: (1) Council Regulation (EC) No 428/2009 ( 2 ) has been substantially amended several times. Since further amendments are to be made, that Regulation should be recast in the interests of clarity, effectiveness and efficiency. (2) This Regulation aims to ensure that in the area of dual-use items, the Union and its Member States fully take into account all relevant considerations. Relevant considerations include international obligations and commitments, obligations under relevant sanctions, considerations of national foreign and security policy including those contained in the Council Common Position 2008/944/CFSP ( 3 ) , among them human rights, and considerations about intended end-use and the risk of diversion. Through this Regulation, the Union demonstrates its commitment to maintaining robust legal requirements with regard to dual-use items, as well as to strengthening the exchange of relevant information and greater transparency. With regard to cyber-surveillance items, the competent authorities of the Member States should consider in particular the risk of them being used in connection with internal repression or the commission of serious violations of human rights and international humanitarian law. (3) This Regulation also aims to strengthen the guidance to be given to exporters, in particular to small and medium-sized enterprises (SMEs), regarding responsible practices, yet without impairing the global competitiveness of exporters of dual-use items or other associated industry or academia which are resident or established in a Member State. (4) United Nations Security Council Resolution 1540 (2004), adopted on 28 April 2004, decided that all States are to take and enforce effective measures to establish domestic controls to prevent the proliferation of nuclear, chemical or biological weapons and their means of delivery, including by establishing appropriate controls over related materials, equipment and technology. Controls are also required under relevant international agreements, such as the Convention on the Prohibition of the Development, Production, Stockpiling and use of Chemical Weapons and on their Destruction (the ‘Chemical Weapons Convention’ or ‘CWC’) and the Convention on the Prohibition of the Development, Production and Stockpiling of Bacteriological (Biological) and Toxin Weapons and On Their Destruction (the ‘Biological and Toxin Weapons Convention’ or ‘BWC’), and in line with commitments agreed upon in multilateral export control regimes. (5) An effective common system of export controls on dual-use items is therefore necessary to ensure that the international commitments and responsibilities of the Member States and of the Union, in particular regarding non-proliferation, regional peace, security and stability and respect for human rights and international humanitarian law, are complied with. (6) The EU Strategy against proliferation of Weapons of Mass Destruction of 12 December 2003 (‘EU WMD Strategy’) emphasises the Union’s commitment to strong national and internationally coordinated export controls. (7) The contribution of exporters, brokers, providers of technical assistance or other relevant stakeholders to the overall aim of trade controls is crucial. In order for them to be able to act in conformity with this Regulation, the assessment of risks related to transactions concerned by this Regulation is to be carried out through transaction-screening measures, also known as the due diligence principle, as a part of an Internal Compliance Programme (ICP). In that regard, in particular the size and organisational structure of exporters have to be taken into account when developing and implementing ICPs. (8) In order to address the risk that certain non-listed cyber-surveillance items exported from the customs territory of the Union might be misused by persons complicit in or responsible for directing or committing serious violations of human rights or international humanitarian law, it is appropriate to place the export of such items under control. Associated risks relate, in particular, to cases where cyber-surveillance items are specially designed to enable intrusion or deep packet inspection into information and telecommunications systems in order to conduct covert surveillance of natural persons by monitoring, extracting, collecting or analysing data, including biometrics data, from those systems. Items used for purely commercial applications such as billing, marketing, quality services, user satisfaction or network security are generally considered not to entail such risks. (9) With a view to strengthening the effective control of exports of non-listed cyber-surveillance items, it is essential to further harmonise the application of catch-all controls in that area. To that end, Member States are committed to supporting such controls by sharing information amongst themselves and with the Commission, in particular regarding technological developments of cyber-surveillance items, and by exercising vigilance in the application of such controls to promote an exchange at Union level. (10) In order to enable the Union to react rapidly to the serious misuse of existing technologies or to new risks associated with emerging technologies, a mechanism should be introduced to enable Member States to coordinate their responses when a new risk is identified. Such coordination should be followed by initiatives to introduce equivalent controls at the multilateral level in order to broaden the response to the identified risk. (11) Transmission of dual-use software and technology by means of electronic media, fax or telephone to destinations outside the customs territory of the Union should also be controlled. In order to limit the administrative burden for exporters and the competent authorities of the Member States, general or global licenses or harmonised interpretations of provisions should be provided for certain transmissions, such as transmissions to a cloud. (12) Considering the important role of customs authorities in the enforcement of export controls, the terms used in this Regulation should, to the extent possible, be consistent with the definitions set out in Regulation (EU) No 952/2013 of the European Parliament and of the Council ( 4 ) (the ‘Union Customs Code’). (13) Various categories of persons can be involved in the export of dual-use items, including natural persons such as service providers, researchers, consultants and persons transmitting dual-use items electronically. It is essential that all such persons are aware of the risks associated with the export and the provision of technical assistance regarding sensitive items. In particular, academic and research institutions face distinct challenges in export control due to, inter alia, their general commitment to the free exchange of ideas, the fact that their research work often involves cutting edge technologies, their organisational structures and the international nature of their scientific exchanges. Member States and the Commission should, where necessary, raise awareness among the academic and research community and provide them with tailored guidance to address those distinct challenges. In alignment with multilateral export control regimes, the implementation of controls s', '{"source_registry_version":"2026-06-26","authority":"European Union / EUR-Lex","domain":"export_control","tags":["dual-use","export-control","cyber-surveillance","sensitive-technology"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://publications.europa.eu/resource/celex/32021R0821.ENG","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:39.722Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('us-ecfr-cosmetic-labeling-21-cfr-701', '21 CFR Part 701 Cosmetic Labeling', 'https://www.ecfr.gov/current/title-21/chapter-I/subchapter-G/part-701', 'U.S. Electronic Code of Federal Regulations', 'US', 'cosmetics', 'regulation', 'high', '["cosmetics","labeling","ingredient-declaration","warning"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('us-ecfr-cosmetic-labeling-21-cfr-701', 'bce643a16d8b9ac7e42f3c6568ddccb8451fc2135e799071ce262a6bf32c9e27', '2026-06-25T13:32:21.977Z', true, 57747, 49979, 'data/knowledge/documents/us-ecfr-cosmetic-labeling-21-cfr-701.md', 'PART 701—COSMETIC LABELING Authority: 21 U.S.C. 321, 352, 361, 362, 363, 371, 374; 15 U.S.C. 1454, 1455. Source: 39 FR 10056, Mar. 15, 1974, unless otherwise noted. Subpart A—General Provisions § 701.1 Misbranding. (a) Among representations in labeling of a cosmetic which render such cosmetic misbranded is a false or misleading representation with respect to another cosmetic or a food, drug, or device. (b) The labeling of a cosmetic which contains two or more ingredients may be misleading by reason (among other reasons) of the designation of such cosmetic in such labeling by a name which includes or suggests the name of one or more but not all such ingredients, even though the names of all such ingredients are stated elsewhere in the labeling. § 701.2 Form of stating labeling requirements. (a) A word, statement, or other information required by or under authority of the Act to appear on the label may lack that prominence and conspicuousness required by section 602(c) of the Act by reason (among other reasons) of: (1) The failure of such word, statement, or information to appear on the part or panel of the label which is presented or displayed under customary conditions of purchase; (2) The failure of such word, statement, or information to appear on two or more parts or panels of the label, each of which has sufficient space therefor, and each of which is so designed as to render it likely to be, under customary conditions of purchase, the part or panel displayed; (3) The failure of the label to extend over the area of the container or package available for such extension, so as to provide sufficient label space for the prominent placing of such word, statement, or information; (4) Insufficiency of label space (for the prominent placing of such word, statement, or information) resulting from the use of label space for any word, statement, design, or device which is not required by or under authority of the Act to appear on the label; (5) Insufficiency of label space (for the prominent placing of such word, statement, or information) resulting from the use of label space to give materially greater conspicuousness to any other word, statement, or information, or to any design or device; (6) Smallness or style of type in which such word, statement, or information appears, insufficient background contrast, obscuring designs or vignettes, or crowding with other written, printed, or graphic matter. (b)(1) All words, statements, and other information required by or under authority of the Act to appear on the label or labeling shall appear thereon in the English language: Provided, however, That in the case of articles distributed solely in the Commonwealth of Puerto Rico or in a Territory where the predominant language is one other than English, the predominant language may be substituted for English. (2) If the label contains any representation in a foreign language, all words, statements, and other information required by or under authority of the Act to appear on the label shall appear thereon in the foreign language. (3) If the labeling contains any representation in a foreign language, all words, statements, and other information required by or under authority of the Act to appear on the label or labeling shall appear on the labeling in the foreign language. § 701.3 Designation of ingredients. (a) The label on each package of a cosmetic shall bear a declaration of the name of each ingredient in descending order of predominance, except that fragrance or flavor may be listed as fragrance or flavor. An ingredient which is both fragrance and flavor shall be designated by each of the functions it performs unless such ingredient is identified by name. No ingredient may be designated as fragrance or flavor unless it is within the meaning of such term as commonly understood by consumers. Where one or more ingredients is accepted by the Food and Drug Administration as exempt from public disclosure pursuant to the procedure established in § 720.8(a) of this chapter, in lieu of label declaration of identity the phrase “and other ingredients” may be used at the end of the ingredient declaration. (b) The declaration of ingredients shall appear with such prominence and conspicuousness as to render it likely to be read and understood by ordinary individuals under normal conditions of purchase. The declaration shall appear on any appropriate information panel in letters not less than 1/16 of an inch in height and without obscuring design, vignettes, or crowding. In the absence of sufficient space for such declaration on the package, or where the manufacturer or distributor wishes to use a decorative container, the declaration may appear on a firmly affixed tag, tape, or card. In those cases where there is insufficient space for such declaration on the package, and it is not practical to firmly affix a tag, tape, or card, the Commissioner may establish by regulation an acceptable alternate, e.g., a smaller type size. A petition requesting such a regulation as an amendment to this paragraph shall be submitted pursuant to part 10 of this chapter. (c) A cosmetic ingredient shall be identified in the declaration of ingredients by: (1) The name specified in § 701.30 as established by the Commissioner for that ingredient for the purpose of cosmetic ingredient labeling pursuant to paragraph (e) of this section; (2) In the absence of the name specified in § 701.30, the name adopted for that ingredient in the following editions and supplements of the following compendia, listed in order as the source to be utilized: (i) CTFA (Cosmetic, Toiletry and Fragrance Association, Inc.) Cosmetic Ingredient Dictionary, Second Ed., 1977 (available from the Cosmetic, Toiletry and Fragrance Association, Inc. 1110 Vermont Ave. NW., Suite 800, Washington, DC 20005, or at the National Archives and Records Administration (NARA), which is incorporated by reference, except for the following deletions and revisions. (For information on the availability of this material at NARA, call 202-741-6030, or go to: http://www.archives.gov/federal_register/code_of_federal_regulations/ibr_locations.html. ) ( a ) The following names are not adopted for the purpose of cosmetic ingredient labeling: Acid Black 58 Acid Black 107 Acid Black 139 Acid Blue 168 Acid Blue 170 Acid Blue 188 Acid Blue 209 Acid Brown 19 Acid Brown 30 Acid Brown 44 Acid Brown 45 Acid Brown 46 Acid Brown 48 Acid Brown 224 Acid Orange 80 Acid Orange 85 Acid Orange 86 Acid Orange 88 Acid Orange 89 Acid Orange 116 Acid Red 131 Acid Red 213 Acid Red 252 Acid Red 259 Acid Violet 73 Acid Violet 76 Acid Violet 99 Acid Yellow 114 Acid Yellow 127 Direct Yellow 81 Solvent Black 5 Solvent Brown 43 Solvent Yellow 63 Solvent Yellow 90 ( b ) The following names are adopted for the purpose of cosmetic ingredient labeling, provided the respective monographs are revised to describe their otherwise disclosed chemical compositions, or describe their chemical compositions more precisely, and such revised monographs are published in supplements to this dictionary edition by July 18, 1980. Acid Black 2 Benzophenone-11 Carbomer 934 Carbomer 934P Carbomer 940 Carbomer 941 Carbomer 960 Carbomer 961 Chlorofluorocarbon 11S Dimethicone Copolyol Disperse Red 17 Pigment Green 7 Polyamino Sugar Condensate SD Alcohol (all 27 alphanumeric designations) Sodium Chondroitin Sulfate Synthetic Beeswax ( c ) The following names are adopted for the purpose of cosmetic ingredient labeling until January 19, 1981. Amphoteric (all 20 numeric designations) Quaternium (all 49 numeric designations) (ii) United States Pharmacopeia, 19th Ed., 1975, and Second Supplement to the USP XIX and NF XIV, 1976. (Copies are available from the U.S. Pharmacopeial Convention, Inc., 12601 Twinbrook Parkway, Rockville, MD 20852, or at the National Archives and Records Administration (NARA). For information on the availability of this material at NARA, call 202-741-6030, or go to: http://www.archives.g', '{"source_registry_version":"2026-06-26","authority":"U.S. Electronic Code of Federal Regulations","domain":"cosmetics","tags":["cosmetics","labeling","ingredient-declaration","warning"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.ecfr.gov/current/title-21/chapter-I/subchapter-G/part-701","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:32:21.977Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
