insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('jp-customs-tariff-schedule', '92da51c64ba9942ba8e731a05be392ea25b5d0d39837a04afda7030977f0db70', '2026-06-25T13:32:32.472Z', true, 53654, 13718, 'data/knowledge/documents/jp-customs-tariff-schedule.md', 'Japan''s Tariff Schedule ( Statistical Code for Import ) : Japan Customs Skip to Content Menu Home Passenger Export / Import Enforcement Trade Statistics Customs Answer(FAQ) Regional Customs Hakodate Tokyo Yokohama Nagoya Osaka Kobe Moji Nagasaki Okinawa Site Map Japanese Site Map Japanese Location: > Japan''s Tariff Schedule ( Statistical Code for Import ) tweet Japan''s Tariff Schedule ( Statistical Code for Import ) April 1, 2026 January 1, 2026 April 1, 2025 January 1, 2025 April 1, 2024 February 1, 2024 January 1, 2024 April 1, 2023 February 21, 2023 January 1, 2023 December 8, 2022 December 1, 2022 November 29, 2022 Apr 1, 2022 Jan 1, 2022 Oct 22, 2021 Sep 19, 2021 Apr 1, 2021 Jan 1, 2021 Oct 1, 2020 June 27, 2020 April 1, 2020 January 1, 2020 April 1, 2019 February 1, 2019 January 14, 2019 December 30, 2018 April 1, 2018 January 1, 2018 May 16, 2017 April 1, 2017 January 1, 2017 June 7, 2016 April 1, 2016 January 1, 2016 April 1, 2015 January 15, 2015 January 1, 2015 April 1, 2014 January 1, 2014 April 1, 2013 January 1, 2013 April 1, 2012 March 1, 2012 January 1, 2012 August 1, 2011 April 1, 2011 January 1, 2011 April 1, 2010 January 1, 2010 June 1, 2009 April 1, 2009 January 1, 2009 April 1, 2008 January 1, 2008 April 1, 2007 tweet Top of Page Top of Page Notice Privacy Policy Inquiry Customs and Tariff Bureau, 3-1-1 Kasumigaseki, Chiyoda-ku, Tokyo 100-8940, JAPAN Copyright(C) Ministry of Finance Japan Japan''s Tariff Schedule as of April 1 2026 : Japan Customs Skip to Content Menu Home Passenger Export / Import Enforcement Trade Statistics Customs Answer(FAQ) Regional Customs Hakodate Tokyo Yokohama Nagoya Osaka Kobe Moji Nagasaki Okinawa Site Map Japanese Site Map Japanese Location: Home > Japan''s Tariff Schedule ( Statistical Code for Import ) > Japan''s Tariff Schedule as of April 1 2026 tweet Japan''s Tariff Schedule as of April 1 2026 This information is for reference only, not for official use. Please refer to the relevant statutory publications in Japanese for confirmation. If you have an inquiry regarding customs formalities, etc., please feel free to ask a customs counselor at the nearest Customs office. Abbreviation of unit SECTION I LIVE ANIMALS; ANIMAL PRODUCTS Chapter 1 Live animals. Tariff rate Chapter 2 Meat and edible meat offal. Tariff rate Chapter 3 Fish and crustaceans, molluscs and other aquatic invertebrates. Tariff rate Chapter 4 Dairy produce; birds'' eggs; natural honey; edible products of animal origin, not elsewhere specified or included. Tariff rate Chapter 5 Products of animal origin, not elsewhere specified or included. Tariff rate SECTION II VEGETABLE PRODUCTS Chapter 6 Live trees and other plants; bulbs, roots and the like; cut flowers and ornamental foliage. Tariff rate Chapter 7 Edible vegetables and certain roots and tubers. Tariff rate Chapter 8 Edible fruit and nuts; peel of citrus fruit or melons. Tariff rate Chapter 9 Coffee, tea, mate and spices. Tariff rate Chapter 10 Cereals. Tariff rate Chapter 11 Products of the milling industry; malt; starches; inulin; wheat gluten. Tariff rate Chapter 12 Oil seeds and oleaginous fruits; miscellaneous grains, seeds and fruit; industrial or medicinal plants; straw and fodder. Tariff rate Chapter 13 Lac; gums, resins and other vegetable saps and extracts. Tariff rate Chapter 14 Vegetable plaiting materials; vegetable products not elsewhere specified or included. Tariff rate SECTION III ANIMAL, VEGETABLE OR MICROBIAL FATS AND OILS AND THEIR CLEAVAGEPRODUCTS; PREPARED EDIBLE FATS; ANIMAL OR VEGETABLE WAXES Chapter 15 Animal, vegetable or microbial fats and oils and their cleavage products; prepared edible fats; animal or vegetable waxes. Tariff rate SECTION IV PREPARED FOODSTUFFS; BEVERAGES, SPIRITS AND VINEGAR; TOBACCO AND MANUFACTURED TOBACCO SUBSTITUTES; PRODUCTS, WHETHER OR NOT CONTAINING NICOTINE, INTENDED FOR INHALATION WITHOUT COMBUSTION; OTHER NICOTINE CONTAINING PRODUCTS INTENDED FOR THE INTAKE OF NICOTINE INTO THE HUMAN BODY Chapter 16 Preparations of meat, of fish, crustaceans, molluscs or other aquatic invertebrates, or of insects. Tariff rate Chapter 17 Sugars and sugar confectionery. Tariff rate Chapter 18 Cocoa and cocoa preparations. Tariff rate Chapter 19 Preparations of cereals, flour, starch or milk; pastrycooks'' products. Tariff rate Chapter 20 Preparations of vegetables, fruit, nuts or other parts of plants. Tariff rate Chapter 21 Miscellaneous edible preparations. Tariff rate Chapter 22 Beverages, spirits and vinegar. Tariff rate Chapter 23 Residues and waste from the food industries; prepared animal fodder. Tariff rate Chapter 24 Tobacco and manufactured tobacco substitutes; products, whether or not containing nicotine, intended for inhalation without combustion; other nicotine containing products intended for the intake of nicotine into the human body. Tariff rate SECTION V MINERAL PRODUCTS Chapter 25 Salt; sulphur; earths and stone; plastering materials, lime and cement. Tariff rate Chapter 26 Ores, slag and ash. Tariff rate Chapter 27 Mineral fuels, mineral oils and products of their distillation; bituminous substances; mineral waxes. Tariff rate SECTION VI PRODUCTS OF THE CHEMICAL OR ALLIED INDUSTRIES Chapter 28 Inorganic chemicals; organic or inorganic compounds of precious metals, of rare-earth metals, of radioactive elements or of isotopes. Tariff rate Chapter 29 Organic chemicals. Tariff rate Chapter 30 Pharmaceutical products. Tariff rate Chapter 31 Fertilisers. Tariff rate Chapter 32 Tanning or dyeing extracts; tannins and their derivatives; dyes, pigments and other colouring matter; paints and varnishes; putty and other mastics; inks. Tariff rate Chapter 33 Essential oils and resinoids; perfumery, cosmetic or toilet preparations. Tariff rate Chapter 34 Soap, organic surface-active agents, washing preparations, lubricating preparations, artificial waxes, prepared waxes, polishing or scouring preparations, candles and similar articles, modelling pastes, "dental waxes" and dental preparations with a basis of plaster. Tariff rate Chapter 35 Albuminoidal substances; modified starches; glues; enzymes. Tariff rate Chapter 36 Explosives; pyrotechnic products; matches; pyrophoric alloys; certain combustible preparations. Tariff rate Chapter 37 Photographic or cinematographic goods. Tariff rate Chapter 38 Miscellaneous chemical products. Tariff rate SECTION VII PLASTICS AND ARTICLES THEREOF; RUBBER AND ARTICLES THEREOF Chapter 39 Plastics and articles thereof. Tariff rate Chapter 40 Rubber and articles thereof. Tariff rate SECTION VIII RAW HIDES AND SKINS, LEATHER, FURSKINS AND ARTICLES THEREOF; ADDLERY AND HARNESS; TRAVEL GOODS, HANDBAGS AND SIMILAR CONTAINERS; ARTICLES OF ANIMAL GUT (OTHER THAN SILK-WORM GUT) Chapter 41 Raw hides and skins (other than furskins) and leather. Tariff rate Chapter 42 Articles of leather; saddlery and harness; travel goods, handbags and similar containers; articles of animal gut (other than silk-worm gut). Tariff rate Chapter 43 Furskins and artificial fur; manufactures thereof. Tariff rate SECTION IX WOOD AND ARTICLES OF WOOD; WOOD CHARCOAL; CORK AND ARTICLES OF CORK; MANUFACTURES OF STRAW, OF ESPARTO OR OF OTHER PLAITING MATERIALS; BASKETWARE AND WICKERWORK Chapter 44 Wood and articles of wood; wood charcoal. Tariff rate Chapter 45 Cork and articles of cork. Tariff rate Chapter 46 Manufactures of straw, of esparto or of other plaiting materials; basketware and wickerwork. Tariff rate SECTION X PULP OF WOOD OR OF OTHER FIBROUS CELLULOSIC MATERIAL; RECOVERED (WASTE AND SCRAP) PAPER OR PAPERBOARD; PAPER AND PAPERBOARD AND ARTICLES THEREOF Chapter 47 Pulp of wood or of other fibrous cellulosic material; recovered (waste and scrap) paper or paperboard. Tariff rate Chapter 48 Paper and paperboard; articles of paper pulp, of paper or of paperboard. Tariff rate Chapter 49 Printed books, newspapers, pictures and other products of the printing industry; manuscripts, typescripts and plans. Tariff rate SECTION XI TEXTILES AND TE', '{"source_registry_version":"2026-06-26","authority":"Japan Customs","domain":"customs","tags":["hs-code","tariff","classification"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.customs.go.jp/english/tariff/","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:32:32.472Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
