insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('jp-customs-origin-verification', 'f71d5cb09fa4ed1dd99dfbc76372570dd98336c45a56e754d48de040f9110d4c', '2026-06-25T13:02:43.679Z', true, 27618, 5523, 'data/knowledge/documents/jp-customs-origin-verification.md', 'ORIGIN VERIFICATION : Japan Customs Skip to Content Menu Home Passenger Export / Import Enforcement Trade Statistics Customs Answer(FAQ) Regional Customs Hakodate Tokyo Yokohama Nagoya Osaka Kobe Moji Nagasaki Okinawa Site Map Japanese Site Map Japanese Location: Rules of Origin > ORIGIN VERIFICATION ORIGIN VERIFICATION *There are links to PDF files below. (1) Purpose of verification &ldquo;Verification&rdquo; is a process of confirming the originating status of goods which have already been imported under preferential tariff treatment of Economic Partnership Agreements (EPAs) or Generalized System of Preferences (GSP). Customs conducts verification of origin in accordance with the provision of each EPA and Customs-related laws and regulations. In order to benefit from the preferential tariff under an EPA or GSP, the imported good must qualify as originating in accordance with the applicable rules of origin of the EPA or GSP. Through verification, Customs ensures the proper application of preferential tariff treatment under EPAs or GSP. (2) Methods of verification As for the verification with the importer, Customs sends a written request for information on the originating status of the imported good(s). Customs determines whether the good qualifies as originating on the basis of the information and documents provided by the importer. If the originating status of the good is not confirmed through the verification with the importer, Customs may carry out verification with the exporter or producer. Customs sends a written request for information to the exporter or producer, or conducts a verification visit to the premises (e.g. factories or offices) of the exporter or producer. If Customs cannot confirm the originating status of the good through the above process, preferential tariff treatment would be denied. Furthermore, depending on the cases, the good may be subject to an additional tax/penalties for underpayment of Customs duties. (Download Files) Form - REQUEST FOR INFORMATION ON THE ORIGIN OF GOODS Japan Customs sends this form to request information regarding the originating status of the imported goods. This form may be sent to the exporter, producer or the competent authority of the exporting party of an EPA or a GSP beneficiary country, depending on the preferential duty rate claimed by the importer. The addressee of this form is requested to promptly fill out and send back the form to Japan Customs. Reference ・Application of Rules of Origin (ROO) of Japan-EU EPA and Japan-UK EPA to the used product (3) Cases of origin irregularities related to EPA or GSP The followings are reference cases for importers regarding products that were declared for import under the preferential tariff rates under EPA or GSP, but that were found to be NOT originating and not eligible for the preferential tariff rates, through origin verification process by Japan Customs. These cases are published for the purpose of ensuring compliance by importers further, who are required to confirm by themselves whether the products satisfy the rules of origin, even if they have obtained a Certification of Origin issued by the exporting country. Please make the most use of this information. *How to view the cases. Reference cases No. HS code Product EPA/GSP 1 HS 03.03 Fish CPTPP 2 HS 03.06 Frozen shrimps (Head) RCEP (from China) 3 HS 03.07 Salted jellyfishes Japan-Thailand EPA 4 HS 06.04 Dried plants for ornamental purposes Japan-India Comprehensive Partnership Agreement (JICEPA) 5 HS 07.11 Salted vegetables Japan-EU EPA 6 HS 09.01 Coffee beans Japan-Australia EPA 7 HS 1604.14 Preparations of tuna Japan-Thailand EPA 8 HS 1604.15 Preparations of mackerel Japan-ASEAN EPA (from Thailand) 9 HS 1605.20 Deep-fried shrimp cutlets Japan-Thailand EPA 10 HS 17.04 Candies Japan-EU EPA 11 HS 18.05 Cocoa powder Japan-Indonesia EPA 12 HS 19.02 Pasta Japan-EU EPA 13 HS 19.05 Cookies Generalized System of Preferences (GSP) 14 HS 19.05 Snacks Generalized System of Preferences (GSP) 15 HS 19.05 Bakers&rsquo; wares Japan-Indonesia EPA 16 HS 2005.20 Preparations of potatoes Japan-Malaysia EPA 17 HS 20.06 Fruit preserved by sugar Japan-Thailand EPA 18 HS 2008.92 Preparations of fruit (mixtures) Japan-Philippines EPA 19 HS 2009.41 Pineapple juice Japan-EU EPA 20 HS 2009.90 Mixtures of juices Japan-Thailand EPA 21 HS 22.04 Wine Japan-EU EPA 22 HS 2710.19 Lubricant Japan-Thailand EPA 23 HS 2924.29 Pigment intermediate Japan-India Comprehensive Partnership Agreement (JICEPA) 24 HS 2933.69 Agrichemical product Japan-India Comprehensive Partnership Agreement (JICEPA) 25 HS 57.02 Floor coverings Generalized System of Preferences (GSP) 26 HS 57.02 Floor coverings Japan-EU EPA 27 HS 61.10 Articles of apparel, knitted or crocheted Japan-EU EPA 28 HS 62.01 Articles of apparel, not knitted or crocheted CPTPP 29 HS 62.11 Articles of apparel, not knitted or crocheted Japan-ASEAN EPA (from Viet Nam) 30 HS 63.02 Towel Generalized System of Preferences (GSP) 31 HS 63.07 Knitted article Japan-EU EPA About Us Organization Central Customs Laboratory Customs Trainig Institute Regional Customs Jurisdiction and Location Laws,Policy Related Laws Outline of Amendment WTO FTA / EPA CMAA Procedure and Form Customs Procedure Customs Form Other Information Brochure Report PR activities of the Customs Japan Customs X guide line Top of Page Top of Page Notice Privacy Policy Inquiry Customs and Tariff Bureau, 3-1-1 Kasumigaseki, Chiyoda-ku, Tokyo 100-8940, JAPAN Copyright(C) Ministry of Finance Japan', '{"source_registry_version":"2026-06-26","authority":"Japan Customs","domain":"origin_labeling","tags":["origin","fta","verification","customs"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.customs.go.jp/roo/english/verification/index.htm","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T13:02:43.679Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('jp-meti-security-export-control', 'Japan Security Export Control', 'https://www.meti.go.jp/english/policy/external_economy/trade_control/index.html', 'Ministry of Economy, Trade and Industry', 'JP', 'export_control', 'regulation_index', 'high', '["export-control","dual-use","security","high-tech"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('jp-meti-security-export-control', '78250ac818ee7b8b520684a384fb1b474b08b139916dbf992443973a843f095b', '2026-06-25T09:41:53.478Z', false, 8799, 8739, 'data/knowledge/documents/jp-meti-security-export-control.md', 'id: jp-meti-security-export-control url: https://www.meti.go.jp/english/policy/external_economy/trade_control/index.html title: Trade Control / METI Ministry of Economy, Trade and Industry captured_at: 2026-06-25T09:41:52.247Z Contact Us Japanese Site Map Main Content Font sizeSML Easy Web Browsing News Releases Speeches Statistics Policies About METI Japanese Print Home Policies Policy Index Trade Control Trade Control Press Releases and Related Information Overview 1. Purpose of the Policy The Trade Control Policy is implemented for the purpose of enabling proper development of foreign trade, and maintaining peace and safety in Japan as well as in the international community by exercising the minimum necessary control or coordination measures over free trade, while quickly and accurately taking into consideration regulation needs in internal and external policies pertaining to border control and consistency with internal conditions and appropriate measures regarding collateral, and establishing a proper trade control system. 2. Overview/Background of the Policy It is a general rule that international trade should be free, but when taking into consideration national security, the safety and security of the people, and the environment, it is necessary to exercise the minimum necessary control and coordination measures at the border. There has been, in particular, increasing concern regarding the development, usage, and proliferation of weapons of mass destruction (WMDs) by international terrorist organizations since the 9.11 attacks in 2001. Furthermore, in view of increasing international awareness over environmental issues, it is necessary for Japan to continue ongoing appropriate measures in trade control. There is also an increasing need for trade remedy measures in the United States, Europe and Asia. Japan also needs to appropriately execute its trade control policy in adherence with international rules with regard to unfair trade by other countries such as export dumping, and as FTA/EPA negotiations accelerate, there are increasing calls for the formulation and implementation of a system to issue certificates of origin. In order to handle such issues, the Ministry of Economy, Trade and Industry exercises the following policies. (1) Trade Control based on the Foreign Exchange and Foreign Trade Law Exercise of proper trade control by way of appropriate implementation of measures that are in compliance with the Foreign Exchange and Foreign Trade Law, such as screening for import/export permission and approval, and on-site inspection and disposal of illegal exports. Policy also undergoes continuous updates. Furthermore, Japan actively exchanges information with other countries, and collects information concerning the situation of circumventing exports to countries of concern and relevant sensitive technology that may be targeted for circumventing export , in order to increase effectiveness in trade control. Japan also acknowledges the importance in cooperating with other countries in introducing an export control systems, and is conducting outreach activities for government officials and industries in Asian countries to increase awareness. And the Government also reviews the export control system and items of export control in accordance with other countries, by participating in the international export control regimes. (2) Appropriate Implementation of Trade Remedies The Government prevents unfair damage to its industry and maintains a fair trade environment by appropriately exercising trade remedy measures in compliance with WTO Agreements and the Customs Tariff Act. It also researches and analyzes laws, guidelines, specific cases, and duty imposition processes. (3) Appropriate Maintenance of Internal Rules pertaining to Certificates of Origin The Government adjusts and thoroughly establishes internal procedures in issuing certificates of origin. Press Releases and Related Information Sanctions North Korea Extension of Ban on Imports from and Exports to North Korea, Pursuant to the Foreign Exchange and Foreign Trade Act (April 8, 2025) Extension of Ban on Imports from and Exports to North Korea, Pursuant to the Foreign Exchange and Foreign Trade Act (April 7, 2023) Response to the situation in Ukraine In view of the current international situation over Ukraine, and for the purpose of contributing to the international efforts for achieving international peace aimed at a solution of the issue, export and import measures have been introduced under the Foreign Exchange and Foreign Trade Act in line with the measures taken by other major countries. Japan’s Export and Import measures against Russia and Belarus (Overview)(PDF:124KB) Details of the measures are provided in the web site below (available only in Japanese). Measures related to the situation in Ukraine End User List Review of the End User List Providing Information on Foreign Entities for which Verification of Transaction Status is Required Regarding the Development of Weapons of Mass Destruction and Missiles or Conventional Weapons (September 29, 2025) Review of the End User List Providing Information on Foreign Entities for which Concern Cannot be Eliminated Regarding the Development of Weapons of Mass Destruction and Missiles (January 31, 2025) Review of the End User List (December 6, 2023) Review of the End User List (November 4, 2022) Trade Remedy Decision to Extend the Taxable Period of Anti-Dumping Duties on Polyethylene Terephthalate with a High Degree of Polymerization Originating in the People’s Republic of China (January 31, 2023) Decision to Impose Anti-Dumping Duties on Hot-dipped Galvanized Steel Wire Originating in the Republic of Korea and the People’s Republic of China (December 2, 2022) Others Annual Report on the Status of the Approval of Overseas Transfers of Defense Equipment and Technology (April 6, 2026) 32nd Asian Export Control Seminar Held (February 10, 2026) Cabinet Decision on the Cabinet Order to Partially Amend the Export Trade Control Order (November 14, 2025) Cabinet Decision on the Cabinet Order to Partially Amend the Export Trade Control Order (November 11, 2025) Measures Based on the Foreign Exchange and Foreign Trade Act Following the United Nations Security Council Resolutions on Iran (September 29, 2025) Guidance for the Control of Sensitive Technologies for Security Export (for Academic and Research Institutions) Amended (September 24, 2025) Cabinet Decision on the Cabinet Order to Partially Amend the Foreign Exchange Order (April 4, 2025) Cabinet Decision on the Cabinet Order to Partially Amend the Foreign Exchange Order and the Export Trade Control Order (March 25, 2025) 31st Asian Export Control Seminar Held (February 28, 2025) The 30th Asian Export Control Seminar was Held (February 22, 2024) METI Joined Japan-US-ROK Export Control Dialogue (February 22, 2024) Japan-Korea Export Control Policy Dialogue Held (July 11, 2023) Cabinet Decision on the Cabinet Order to Partially Amend the Export Trade Control Order (June 27, 2023) Call for Public Comments on the Bill for the Cabinet Order to Partially Amend the Export Trade Control Order (Revision of the Export Control Operation for the Republic of Korea) (April 28, 2023) Japan-Korea Export Control Policy Dialogue Held (April 25, 2023) Japan-Korea Export Control Policy Dialogue Held (April 14, 2023) Circular Notice on Partial Amendment to the Circular Notice on the Operation of the Cabinet Order on Export Trade Control and other circular notices (Review of Export Control to South Korea) (March 23, 2023) Japan-Korea Export Control Policy Dialogue Held (March 16, 2023) Resources Trade Control Policy Division (in Japanese) Security Export Control Policy Division Center for Information on Security Trade Controls Japan Machinery Center for Trade and Investment Contact Point Trade Control Policy Division, Trade and Economic Security Bureau For inquiries regarding issues other than Security Export Control + 81', '{"source_registry_version":"2026-06-26","authority":"Ministry of Economy, Trade and Industry","domain":"export_control","tags":["export-control","dual-use","security","high-tech"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://www.meti.go.jp/english/policy/external_economy/trade_control/index.html","extra_fetched_urls":[],"cache_days":30,"cache_expires_at":"2026-07-25T09:41:53.478Z","cache_status":"fresh","browser_capture_path":"data/knowledge/browser-captures/jp-meti-security-export-control.txt","screenshot_path":"data/knowledge/browser-captures/jp-meti-security-export-control.png"}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
