insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-nmpa-cosmetics-hub', '86e2575036b289c2136d609fa12c1de92cbe22a6328183413739d23cf2ea3647', '2026-06-25T13:03:12.859Z', true, 15996, 4215, 'data/knowledge/documents/cn-nmpa-cosmetics-hub.md', 'Cosmetics 中文 | Contact Us | search search nav Home + About NMPA + Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News + Drugs + Medical Devices + Cosmetics + Resources + Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Home > Cosmetics Requirements for the Pilot Program of Electronic Labels for Cosmetics 2025-12-24 To regulate the pilot program for electronic labels for cosmetics (including toothpaste, hereinafter referred to as "cosmetics"), these Requirements are formulated in accordance with the provisions of the Regulations on Supervision and Administration of Cosmetics (hereinafter referred to as the "Regulations"), the Provisions for Registration and Filing of Cosmetics, the Provisions for Supervision and Administration of Manufacturing and Marketing of Cosmetics, the Provisions for Toothpaste Regulation, and the Measures for the Administration of Cosmetics Labels. NMPA Announcement on Issuing the Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 The release of the Opinions is an important measure by the NMPA to implement the strategic deployment of the Party Central Committee and the State Council on comprehensive deepening of reform and promoting high-quality development. It will better safeguard the people''s demand for cosmetics and inject a strong impetus into the high-quality development of the cosmetics industry. NMPA’s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 To further coordinate high-quality development and high-level safety in the cosmetics sector, and thereby better meet the people''s new expectations for a better life in the new era, the following opinions are proposed to deepen the reform of cosmetics regulation and promote the high-quality development of the cosmetics industry. Policy Interpretation of the NMPA’s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 To thoroughly implement the important instructions of General Secretary Xi Jinping on drug regulation and industrial development, further coordinate high-quality development and high-level safety in the cosmetics sector, and thereby better meet the people''s new expectations for a better life in the new era, the NMPA has issued the NMPA''s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development (hereinafter referred to as the Opinions). The key points are interpreted as follows. NMPA Notice on Conducting a Pilot Program for Electronic Labeling of Cosmetics GYJZ [2025] No.16 2025-11-28 The National Medical Products Administration (NMPA) has decided to carry out a pilot program for cosmetic electronic labeling in accordance with the Regulations on Supervision and Administration of Cosmetics (hereinafter referred to as the "Regulations"). The relevant matters are hereby notified as follows. Announcement of the National Medical Products Administration (NMPA) on Matters Related to the Administration of the Inventory of Existing Cosmetic Ingredients (IECIC) (No. 61 of 2025) 2025-07-21 To implement the Regulations on Supervision and Administration of Cosmetics, further regulate the administration of cosmetic ingredients, and encourage innovation in raw materials, the following matters concerning the Inventory of Existing Cosmetic Ingredients (hereinafter referred to as the Inventory) are hereby announced. 1 2 3 ... 6 > Policies Interpretation Procedure for Information Sharing Between Regulatory Agencies Policy measures to advance drug, medical device regulation reform Must read for foreign investors in China Newsletter Volume I 2026 Volume VI 2025 2025 Special Issue for Cosmetics Volume V 2025 Volume IV 2025 About NMPA Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News Drugs Medical Devices Cosmetics Resources Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Copyright © National Medical Products Administration All rights reserved. Presented by China Daily. 京ICP备13027807号-2', '{"source_registry_version":"2026-06-26","authority":"National Medical Products Administration","domain":"cosmetics","tags":["cosmetics","china","nmpa","notices"],"format":"html","page_count":null,"parse_error":null,"fetched_url":"https://english.nmpa.gov.cn/cosmetics.html","extra_fetched_urls":[],"cache_days":14,"cache_expires_at":"2026-07-09T13:03:12.859Z","cache_status":"fresh","browser_capture_path":null,"screenshot_path":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
