) system in phases since 2019. Starting July 1, 2024, PIFs have been required for sunscreens, hair dyes, perm agents, antiperspirants, and home-use too"}'::jsonb, '운영자가 주기적으로 감시해야 하는 대만 핵심 소스입니다.', null, null, null, '{"generated_by":"scripts/detect-regulatory-updates.mjs","source_registry_version":"2026-06-26","source_tags":["pif","safety-assessment","2026"],"compact_title":"cosmetic-product-information-files-to-be-implemented-in-phases","update_queue_generated_at":"2026-06-25T17:40:27.672Z","crawl_generated_at":"2026-06-25T17:40:27.672Z"}'::jsonb) on conflict (candidate_key) do update set source_key = excluded.source_key, title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, source_priority = excluded.source_priority, change_type = excluded.change_type, severity = excluded.severity, status = excluded.status, detected_at = excluded.detected_at, fetched_at = excluded.fetched_at, cache_expires_at = excluded.cache_expires_at, previous_hash = excluded.previous_hash, current_hash = excluded.current_hash, affected_domains = excluded.affected_domains, affected_terms = excluded.affected_terms, affected_products = excluded.affected_products, evidence = excluded.evidence, next_action = excluded.next_action, reviewer_notes = excluded.reviewer_notes, decision = excluded.decision, decided_at = excluded.decided_at, metadata = excluded.metadata;
