insert into public.knowledge_terms (term_key, canonical_name, category, identifiers, source_keys, notes, registry_version) values ('tfda-bovine-spongiform-encephalopathy-lanolin-gelatin-fatty-acid-amino-acid-glycerin-', '牛海綿狀腦病(Bovine Spongiform Encephalopathy)發生國家之牛、羊組織製成之原料 (羊毛脂(Lanolin)、英國產以外之乳製品、英國產以外經鹼性處理之明膠(Gelatin)，以及經破壞致病原處理之脂肪酸(Fatty acid)、胺基酸(Amino acid)及甘油(Glycerin)等牛脂(Tallow)衍生物原料不在此限) (1)牛海綿狀腦病發生之國家，以行政院農業委員會公告動物傳染病非疫區及疫區之國家(地區)為準。 (2)牛、羊組織，包括：腦(Brain)、脊椎(Spinal cord)、眼(Eye)、迴腸(Ileum) 、淋巴結(Lymph nodes)、近端結腸(Proximal Colon)、脾臟(Spleen)、扁桃腺(Tonsil)、硬腦膜(Dura mater)、松果腺(Pineal gland)、胎盤(Placenta)、腦脊椎液(Cerebrospinal fluid)、腦下垂體(Pituitary gland)、腎上腺(Adrenal gland)、遠端結腸(Distal colon)、鼻黏膜(Nasal mucosa)、末梢神經(Peripheral nerves)、骨髓(Bone marrow)、肝臟(Liver)、肺臟(Lung)、胰臟(Pancreas)、胸腺(Thymus gland)。', 'prohibited', '{"cas":[],"inci":["牛海綿狀腦病(Bovine Spongiform Encephalopathy)發生國家之牛、羊組織製成之原料 (羊毛脂(Lanolin)、英國產以外之乳製品、英國產以外經鹼性處理之明膠(Gelatin)，以及經破壞致病原處理之脂肪酸(Fatty acid)、胺基酸(Amino acid)及甘油(Glycerin)等牛脂(Tallow)衍生物原料不在此限) (1)牛海綿狀腦病發生之國家，以行政院農業委員會公告動物傳染病非疫區及疫區之國家(地區)為準。 (2)牛、羊組織，包括：腦(Brain)、脊椎(Spinal cord)、眼(Eye)、迴腸(Ileum) 、淋巴結(Lymph nodes)、近端結腸(Proximal Colon)、脾臟(Spleen)、扁桃腺(Tonsil)、硬腦膜(Dura mater)、松果腺(Pineal gland)、胎盤(Placenta)、腦脊椎液(Cerebrospinal fluid)、腦下垂體(Pituitary gland)、腎上腺(Adrenal gland)、遠端結腸(Distal colon)、鼻黏膜(Nasal mucosa)、末梢神經(Peripheral nerves)、骨髓(Bone marrow)、肝臟(Liver)、肺臟(Lung)、胰臟(Pancreas)、胸腺(Thymus gland)。"],"color_index":[]}'::jsonb, '["tfda-info-203"]'::jsonb, 'Generated from TFDA rule tw-cos-203-646', '2026-06-26') on conflict (term_key) do update set canonical_name = excluded.canonical_name, category = excluded.category, identifiers = excluded.identifiers, source_keys = excluded.source_keys, notes = excluded.notes, registry_version = excluded.registry_version;
insert into public.term_aliases (term_key, alias_value, normalized_alias, alias_type, language, jurisdiction, confidence, source, note) values ('tfda-bovine-spongiform-encephalopathy-lanolin-gelatin-fatty-acid-amino-acid-glycerin-', '牛海綿狀腦病(Bovine Spongiform Encephalopathy)發生國家之牛、羊組織製成之原料 (羊毛脂(Lanolin)、英國產以外之乳製品、英國產以外經鹼性處理之明膠(Gelatin)，以及經破壞致病原處理之脂肪酸(Fatty acid)、胺基酸(Amino acid)及甘油(Glycerin)等牛脂(Tallow)衍生物原料不在此限) (1)牛海綿狀腦病發生之國家，以行政院農業委員會公告動物傳染病非疫區及疫區之國家(地區)為準。 (2)牛、羊組織，包括：腦(Brain)、脊椎(Spinal cord)、眼(Eye)、迴腸(Ileum) 、淋巴結(Lymph nodes)、近端結腸(Proximal Colon)、脾臟(Spleen)、扁桃腺(Tonsil)、硬腦膜(Dura mater)、松果腺(Pineal gland)、胎盤(Placenta)、腦脊椎液(Cerebrospinal fluid)、腦下垂體(Pituitary gland)、腎上腺(Adrenal gland)、遠端結腸(Distal colon)、鼻黏膜(Nasal mucosa)、末梢神經(Peripheral nerves)、骨髓(Bone marrow)、肝臟(Liver)、肺臟(Lung)、胰臟(Pancreas)、胸腺(Thymus gland)。', '牛海綿狀腦病 bovine spongiform encephalopathy 發生國家之牛 羊組織製成之原料 羊毛脂 lanolin 英國產以外之乳製品 英國產以外經鹼性處理之明膠 gelatin 以及經破壞致病原處理之脂肪酸 fatty acid 胺基酸 amino acid 及甘油 glycerin 等牛脂 tallow 衍生物原料不在此限 1 牛海綿狀腦病發生之國家 以行政院農業委員會公告動物傳染病非疫區及疫區之國家 地區 為準 2 牛 羊組織 包括 腦 brain 脊椎 spinal cord 眼 eye 迴腸 ileum 淋巴結 lymph nodes 近端結腸 proximal colon 脾臟 spleen 扁桃腺 tonsil 硬腦膜 dura mater 松果腺 pineal gland 胎盤 placenta 腦脊椎液 cerebrospinal fluid 腦下垂體 pituitary gland 腎上腺 adrenal gland 遠端結腸 distal colon 鼻黏膜 nasal mucosa 末梢神經 peripheral nerves 骨髓 bone marrow 肝臟 liver 肺臟 lung 胰臟 pancreas 胸腺 thymus gland', 'official_rule_name', 'und', 'TW', 0.950, 'tfda-rule', null) on conflict (term_key, normalized_alias, language, jurisdiction, alias_type) do update set alias_value = excluded.alias_value, confidence = excluded.confidence, source = excluded.source, note = excluded.note;
